  d10d2Html+='<div style="flex:1;padding:.4rem;text-align:center;border-radius:6px;background:rgba(148,163,184,.08);border:1px solid rgba(148,163,184,.2)"><div style="font-size:1.2rem">☽</div><div style="font-size:.8rem;font-weight:bold">被動型 '+moonCount+'顆</div><div style="font-size:.7rem;opacity:.7">投資/分紅/繼承</div></div>';
