// ===== [UPGRADE: talkTarot DEEP REWRITE END] =====
// ── 5. 星盤白話讀取 ──
function talkNatal(focusType){
  if(!S.natal||!S.natal.planets) return '';
  var np=S.natal.planets, n=S.natal;
  var texts=[];
  var aspects=n.aspects||[];
  
  // 元素統計
  var elCount={火:0,土:0,風:0,水:0};
  var _elMap={'白羊':'火','金牛':'土','雙子':'風','巨蟹':'水','獅子':'火','處女':'土','天秤':'風','天蠍':'水','射手':'火','摩羯':'土','水瓶':'風','雙魚':'水'};
  Object.values(np).forEach(function(p){ if(p.sign && _elMap[p.sign]) elCount[_elMap[p.sign]]++; });
  var dominantEl = Object.entries(elCount).sort(function(a,b){return b[1]-a[1];})[0];
  var weakEl = Object.entries(elCount).sort(function(a,b){return a[1]-b[1];})[0];
  
  // 相位統計
  var goodAsp = aspects.filter(function(a){return a.good;}).length;
  var badAsp = aspects.filter(function(a){return !a.good;}).length;
  
  if(focusType==='love'){
    // 金星星座 — 愛情模式
    var venus=np['金星'];
    if(venus&&venus.sign){
      var venSigns={'白羊':'感情裡衝動直接，喜歡追的感覺','金牛':'對感情忠誠專一，重視安全感','雙子':'喜歡有趣的對話和新鮮感','巨蟹':'重視家庭歸屬和情感安全','獅子':'大方熱情，喜歡浪漫和被重視','處女':'認真但含蓄，用行動表達愛','天秤':'重視平等和美感，不喜歡衝突','天蠍':'深情執著，愛得濃烈','射手':'喜歡自由不被束縛的感情','摩羯':'務實含蓄，對感情有長期規劃','水瓶':'獨立前衛，感情觀不走傳統路線','雙魚':'浪漫感性，容易為愛犧牲'};
      if(venSigns[venus.sign]) texts.push('金星'+venus.sign+'：'+venSigns[venus.sign]);
    }
    // 金星宮位
    if(venus&&venus.house){
      if(venus.house===7) texts.push('金星在伴侶宮，天生有感情魅力，容易吸引到對象');
      else if(venus.house===5) texts.push('金星在戀愛宮，桃花運旺，享受戀愛的感覺');
      else if(venus.house===12) texts.push('金星在隱藏宮，感情可能有隱密或曖昧的面向');
      else if(venus.house===1) texts.push('金星在自我宮，外表有魅力，異性緣好');
    }
    // 火星 — 性吸引力
    var mars=np['火星'];
    if(mars&&mars.house===7) texts.push('火星在伴侶宮，感情火花強但也容易衝突');
    // 月亮 — 情感需求
    var moon=np['月亮'];
    if(moon&&moon.sign){
      var moonLove={'白羊':'需要自主空間，不喜歡被控制','金牛':'渴望穩定和安全感','巨蟹':'需要被呵護和情感依附','天蠍':'情感深沉強烈，需要完全的信任','雙魚':'極度敏感，需要溫柔對待'};
      if(moonLove[moon.sign]) texts.push('月亮'+moon.sign+'：情感上'+moonLove[moon.sign]);
    }
    // 金星相位
    var venusAsp=aspects.filter(function(a){return a.p1==='金星'||a.p2==='金星';});
    var venGoodAsp=venusAsp.filter(function(a){return a.good;});
    var venBadAsp=venusAsp.filter(function(a){return !a.good;});
    if(venGoodAsp.length>=2) texts.push('金星有多個和諧相位，感情運底子好');
    if(venBadAsp.length>=2) texts.push('金星有挑戰相位，感情路上需要多磨練');
    // 第七宮宮頭星座 — 你會吸引什麼類型的對象
    if(n.houses && n.houses[6]){
      var h7Sign=n.houses[6].sign;
      var h7Desc={'白羊':'主動型、有衝勁的對象','金牛':'穩重可靠、重視物質的對象','雙子':'聰明有趣、善於溝通的對象','巨蟹':'溫柔顧家、重感情的對象','獅子':'大方有氣場、喜歡被仰慕的對象','處女':'細心務實、有原則的對象','天秤':'優雅有品味、重視和諧的對象','天蠍':'深情專注、佔有慾強的對象','射手':'自由奔放、有冒險精神的對象','摩羯':'成熟穩重、事業導向的對象','水瓶':'獨立特別、不按牌理的對象','雙魚':'浪漫感性、有藝術氣質的對象'};
      if(h7Sign && h7Desc[h7Sign]) texts.push('第七宮'+h7Sign+'，你容易吸引到'+h7Desc[h7Sign]);
    }
    // 金星逆行
    if(venus && venus.retrograde) texts.push('金星逆行，感情模式偏內斂，可能晚婚或對舊情有執著');
    // 月亮與金星的相位
    var moonVenus=aspects.filter(function(a){return (a.p1==='月亮'&&a.p2==='金星')||(a.p1==='金星'&&a.p2==='月亮');});
    if(moonVenus.length && moonVenus[0].good) texts.push('月亮與金星和諧，情感表達和愛的需求一致，感情和諧度高');
  }
  else if(focusType==='career'){
    // MC天頂
    if(n.mcSign){
      var mcCareer={'白羊':'適合開創性的事業，當領導者','金牛':'適合穩健累積的事業，金融/不動產','雙子':'適合溝通傳播類工作，寫作/媒體','巨蟹':'適合照顧人的工作，教育/餐飲/醫療','獅子':'適合站上舞台的工作，表演/管理/品牌','處女':'適合精細的專業工作，分析/醫療/技術','天秤':'適合人際導向的工作，法律/公關/設計','天蠍':'適合深入研究的工作，心理/調查/金融','射手':'適合有視野的工作，教育/出版/國際','摩羯':'適合有結構的事業，企業管理/政府/建築','水瓶':'適合創新的領域，科技/社會改革','雙魚':'適合有靈性的工作，藝術/療癒/公益'};
      if(mcCareer[n.mcSign.name]) texts.push('天頂'+n.mcSign.name+'：'+mcCareer[n.mcSign.name]);
    }
    // 太陽宮位
    var sun=np['太陽'];
    if(sun){
      if(sun.house===10) texts.push('太陽在事業宮，天生適合在公眾場合發光');
      else if(sun.house===6) texts.push('太陽在工作宮，在日常工作中找到自我價值');
      else if(sun.house===1) texts.push('太陽在自我宮，事業要以自我品牌為核心');
    }
    // 土星
    var saturn=np['土星'];
    if(saturn){
      if(saturn.house===10) texts.push('土星在事業宮，責任重但最終會有紮實的成就');
      else if(saturn.house===6) texts.push('土星在工作宮，工作環境可能辛苦但磨練出真本事');
    }
    // 木星
    var jupiter=np['木星'];
    if(jupiter&&[1,4,7,10].includes(jupiter.house)) texts.push('木星在角宮，事業擴張力好，有貴人相助');
  }
  else if(focusType==='wealth'){
    var jupiter2=np['木星'];
    if(jupiter2){
      if(jupiter2.house===2) texts.push('木星在財富宮，天生有正財福氣');
      else if(jupiter2.house===8) texts.push('木星在共有資源宮，有偏財和投資運');
      else if(jupiter2.house===11) texts.push('木星在人脈宮，透過社交和人脈帶來財運');
    }
    var venus2=np['金星'];
    if(venus2&&venus2.house===2) texts.push('金星在財富宮，物質運好，容易享受生活');
    var saturn2=np['土星'];
    if(saturn2&&saturn2.house===2) texts.push('土星在財富宮，年輕時財運辛苦但中年後穩步上升');
  }
  else if(focusType==='health'){
    var sun3=np['太陽'];
    var mars3=np['火星'];
    var saturn3=np['土星'];
    if(sun3&&sun3.house===6) texts.push('太陽在健康宮，身體是你這輩子需要關注的課題');
    if(mars3&&[6,8].includes(mars3.house)) texts.push('火星在困難宮位，注意發炎和外傷');
    if(saturn3&&[6,8].includes(saturn3.house)) texts.push('土星在困難宮位，注意慢性病和關節');
  }
  else if(focusType==='relationship'){
    // 第11宮（人脈宮）
    var jupiter4=np['木星'];
    if(jupiter4&&jupiter4.house===11) texts.push('木星在人脈宮，社交圈品質好，朋友帶來好運');
    else if(jupiter4&&jupiter4.house===7) texts.push('木星在合作宮，一對一的關係很順利');
    var venus4=np['金星'];
    if(venus4&&[3,7,11].includes(venus4.house)) texts.push('金星在人際相關宮位，天生有人緣和社交魅力');
    var saturn4=np['土星'];
    if(saturn4&&saturn4.house===11) texts.push('土星在人脈宮，朋友少但都是真心的。社交需要時間經營');
    var mars4=np['火星'];
    if(mars4&&[7,11].includes(mars4.house)) texts.push('火星在人際宮位，社交有衝勁但也容易起衝突');
    // 月亮（情緒安全感 → 影響人際互動模式）
    var moon4=np['月亮'];
    if(moon4&&moon4.sign){
      var moonRel={'白羊':'社交中喜歡當主導者','金牛':'重視穩定的朋友關係','雙子':'善於溝通、朋友圈廣','巨蟹':'重感情、會照顧朋友','獅子':'在社交中喜歡被注目','天秤':'天生的社交高手，重視和諧','天蠍':'對朋友忠誠但也有控制欲','水瓶':'社交觀獨立前衛，不走傳統路線'};
      if(moonRel[moon4.sign]) texts.push('月亮'+moon4.sign+'：'+moonRel[moon4.sign]);
    }
  }
  else if(focusType==='family'){
    // 第4宮（家庭宮）
    var moon5=np['月亮'];
    if(moon5&&moon5.house===4) texts.push('月亮在家庭宮，跟家人感情深厚，家是你最大的安全感來源');
    else if(moon5&&moon5.house===10) texts.push('月亮在事業宮，事業和家庭的平衡是你的課題');
    var saturn5=np['土星'];
    if(saturn5&&saturn5.house===4) texts.push('土星在家庭宮，家庭責任重，可能早熟或要照顧家人');
    var jupiter5=np['木星'];
    if(jupiter5&&jupiter5.house===4) texts.push('木星在家庭宮，家庭運好，住家環境舒適');
  }
  
  // 通用：上升星座
  if(n.ascSign){
    var ascMap={'白羊':'有活力、直接','金牛':'穩重、可靠','雙子':'聰明、善談','巨蟹':'溫暖、親切','獅子':'有氣場、自信','處女':'細緻、專業','天秤':'優雅、好相處','天蠍':'神秘、有深度','射手':'開朗、豁達','摩羯':'成熟、有能力','水瓶':'獨特、有想法','雙魚':'溫柔、有同理心'};
    if(ascMap[n.ascSign.name]) texts.push('上升'+n.ascSign.name+'：給人'+ascMap[n.ascSign.name]+'的第一印象');
  }
  
  // 元素平衡
  if(dominantEl && dominantEl[1]>=5){
    var elTrait={火:'行動力和熱情充沛，但容易躁',土:'踏實穩重，但有時太固執',風:'思維活躍善溝通，但容易想太多',水:'情感豐富有直覺，但容易情緒化'};
    texts.push(dominantEl[0]+'元素特別旺：'+elTrait[dominantEl[0]]);
  }
  if(weakEl && weakEl[1]<=1){
    var elLack={火:'行動力和自信需要後天培養',土:'穩定性和耐心是功課',風:'溝通表達需要多練習',水:'情緒覺察和同理心需要培養'};
    texts.push('缺'+weakEl[0]+'元素：'+elLack[weakEl[0]]);
  }
  
  // 相位格局
  if(goodAsp >= badAsp + 3) texts.push('星盤相位以和諧為主，人生路上助力多於阻力');
  else if(badAsp >= goodAsp + 3) texts.push('星盤相位挑戰較多，但壓力也是成長的動力');
  
  return texts.slice(0,5).map(function(t){return t.replace(/[。．.]+$/,'');}).join('。')+(texts.length?'。':'');
}

// ── 6. 姓名白話讀取 ──
function talkName(focusType){
  if(!S.nameResult && !S.zodiacNameResult) return '';
  var nr=S.nameResult;
  var zr=S.zodiacNameResult;
  var texts=[];
  
  // ── 1. 三才五格分析 × focusType ──
  if(nr){
    // 人格（主運·中年）
    if(nr.renGe&&nr.renGe.fortune){
      var renLvl=nr.renGe.fortune.level||'';
      var renEl=nr.renGe.el||'';
      if(focusType==='career'){
        if(renLvl==='大吉'||renLvl==='吉') texts.push('姓名人格數理'+nr.renGe.num+'（'+renLvl+'），事業方面有名字能量加持');
        else texts.push('姓名人格數理偏弱，事業上需要靠實力補強');
      } else if(focusType==='love'){
        if(renLvl==='大吉'||renLvl==='吉') texts.push('人格數理好，個人魅力是感情加分項');
      }
    }
    
    // 地格（前運·青年）
    if(nr.diGe&&nr.diGe.fortune){
      var diLvl=nr.diGe.fortune.level||'';
      if(focusType==='career' && (diLvl==='凶'||diLvl==='大凶')){
        texts.push('地格偏弱，年輕時事業起步可能較辛苦，但中年後會好轉');
      }
    }
    
    // 外格（人際·副運）
    if(nr.waiGe&&nr.waiGe.fortune){
      var waiLvl=nr.waiGe.fortune.level||'';
      if(focusType==='love' || focusType==='relationship'){
        if(waiLvl==='大吉'||waiLvl==='吉') texts.push('外格數理好，人際關係和社交運有姓名加持');
        else if(waiLvl==='凶') texts.push('外格偏弱，人際方面需要主動經營');
      }
    }
    
    // 總格（後運·晚年）
    if(nr.zongGe&&nr.zongGe.fortune){
      var zongLvl=nr.zongGe.fortune.level||'';
      if(focusType==='wealth'){
        if(zongLvl==='大吉'||zongLvl==='吉') texts.push('總格數理'+nr.zongGe.num+'（'+zongLvl+'），晚年財運有福氣');
        else texts.push('總格偏弱，長期財富需要靠規劃和紀律');
      }
    }
    
    // 三才配置
    if(nr.sanCaiLevel){
      if(nr.sanCaiLevel==='大吉') texts.push('三才配置大吉（'+nr.sanCai.join('→')+'），天地人相生，名字能量流通順暢');
      else if(nr.sanCaiLevel==='吉') texts.push('三才配置吉（'+nr.sanCai.join('→')+'），姓名能量是加分項');
      else if(nr.sanCaiLevel==='凶') texts.push('三才配置有相剋（'+nr.sanCai.join('→')+'），姓名能量受阻，但不影響根本');
    }
    
    // 八字喜忌交叉
    if(S.bazi && S.bazi.fav && nr.sanCai){
      var fav=S.bazi.fav, unfav=S.bazi.unfav||[];
      var renGeEl=nr.sanCai[1]; // 人格五行
      if(renGeEl && fav.includes(renGeEl)){
        texts.push('人格五行'+renGeEl+'正好是八字喜用神，名字與命盤互相加持');
      } else if(renGeEl && unfav.includes(renGeEl)){
        texts.push('人格五行'+renGeEl+'是八字忌神，名字能量與命盤有些拉扯');
      }
    }
  }
  
  // ── 2. 生肖姓名學 ──
  if(zr){
    var olevel = zr.overallLevel||'';
    if(olevel.includes('大吉')||olevel.includes('旺')){
      texts.push('生肖姓名學判定'+olevel+'，名字環境非常適合'+zr.zodiac+'生存');
    } else if(olevel.includes('吉')){
      texts.push('生肖姓名學判定'+olevel+'，名字環境對'+zr.zodiac+'有利');
    } else if(olevel.includes('凶')||olevel.includes('犧牲')){
      texts.push('生肖姓名學判定'+olevel+'，名字字根與'+zr.zodiac+'有衝突，但不需過度焦慮');
    }
    
    // 犧牲格警告
    if(zr.isSacrifice){
      texts.push('⚠ 名字含犧牲格字根，容易付出多回報少，做事前先評估值不值得');
    }
    
    // 巳亥六衝
    if(zr.isSnakePigClash){
      texts.push('⚠ 名字含巳亥六衝字根，注意人際衝突和意外');
    }
    
    // 吉凶命中統計
    if(zr.positions){
      var totalGood=0, totalBad=0;
      zr.positions.forEach(function(pos){
        pos.charResults.forEach(function(cr){
          cr.hits.forEach(function(h){
            if(h.type==='吉') totalGood++;
            else totalBad++;
          });
        });
      });
      if(totalGood>0 && totalBad===0) texts.push('名字字根全部命中吉象，是難得的好名');
      else if(totalGood > totalBad + 2) texts.push('名字吉象字根多於凶象，整體能量偏正面');
      else if(totalBad > totalGood + 2) texts.push('名字凶象字根偏多，但名字只是命運的一小部分');
    }
  }
  
  // ── 3. 兩派整合 ──
  if(nr && zr){
    var scGood = nr.sanCaiLevel && (nr.sanCaiLevel.includes('吉'));
    var scBad = nr.sanCaiLevel === '凶';
    var znGood = (zr.overallLevel||'').includes('吉') || (zr.overallLevel||'').includes('旺');
    var znBad = (zr.overallLevel||'').includes('凶') || (zr.overallLevel||'').includes('犧牲');
    
    if(scGood && znGood) texts.push('兩派姓名學都判定吉象，名字能量是你的助力');
    else if(scBad && znBad) texts.push('兩派都判定偏弱，但名字影響有限，命運主要靠行動決定');
    else if((scGood && znBad)||(scBad && znGood)) texts.push('兩派結論相反，代表名字的影響較中性，不用太放在心上');
  }
  
  return texts.slice(0,4).map(function(t){return t.replace(/[。．.]+$/,'');}).join('。')+(texts.length?'。':'');
}

