  function mdPush(){ var md=(jy()||{}).currentMD; if(!md) return; var pl=jyPl(md.lord); if(!pl) return; var d=pl.dignity||'neutral'; var dm2={exalted:'旺相',own:'入廟',friend:'得地',neutral:'平',enemy:'失勢',debilitated:'落陷'}; ev.push('吠陀'+(pl.zh||md.lord)+'大運（'+(dm2[d]||d)+'）'); if(d==='exalted'||d==='own') _evScore+=1; else if(d==='debilitated') _evScore-=1; }

