  // ? ? prob (finalProb) ????????,????
  // 判定閾值：chartVerdict 驅動（讀實際命盤事實）
  var _cvGlobal = verdictFromProb(prob, type);
  const great = _cvGlobal.verdict==='good';
  const good  = _cvGlobal.isGood;
  const bad   = _cvGlobal.isBad;

