  ctx.fillText(label,W/2,y1+70);

  // BaZi summary
  const y2=420;
  ctx.textAlign='left';ctx.font='bold 20px "Noto Sans TC",sans-serif';ctx.fillStyle='#D4AF37';
  ctx.fillText('🏮 八字命理',60,y2);
