const AI_WORKER_URL = 'https://jy-ai-proxy.onerkk.workers.dev';
// Admin 身份只透過 admin token 判定，前後端必須一致
const AI_USED_KEY = 'jy_ai_used';

function _aiLocalDate(){
  var d=new Date();
  var y=d.getFullYear();
  var m=String(d.getMonth()+1).padStart(2,'0');
  var day=String(d.getDate()).padStart(2,'0');
  return y+'-'+m+'-'+day;
}
function _aiPersonKey(){
  try{
    var f=(typeof S!=='undefined' && S.form)?S.form:{};
    var parts=[
      f.gender||f.sex||'',
      f.name||f.fullName||'',
      f.year||f.y||'',
      f.month||f.m||'',
      f.day||f.d||'',
      f.hour||f.h||f.time||'',
      f.birth||f.birthDate||''
    ].map(function(x){ return String(x||'').trim(); }).filter(Boolean);
    var raw=parts.join('|') || 'anon';
    var hash=0;
    for(var i=0;i<raw.length;i++) hash=((hash<<5)-hash)+raw.charCodeAt(i), hash|=0;
    return 'p_'+Math.abs(hash);
  }catch(e){ return 'p_anon'; }
}
function _aiUsedToday() {
  try {
    var d=JSON.parse(localStorage.getItem(AI_USED_KEY)||'{}');
    var today=_aiLocalDate();
    var person=_aiPersonKey();
    if(d.date!==today) return false;
    if(d.person===person && d.used) return true;
    if(d.people && d.people[person] && d.people[person].used) return true;
    return false;
  } catch(e){ return false; }
}
function _aiMarkUsed() {
  try{
    var today=_aiLocalDate();
    var person=_aiPersonKey();
    var d=JSON.parse(localStorage.getItem(AI_USED_KEY)||'{}');
    if(d.date!==today) d={date:today,people:{}};
    if(!d.people||typeof d.people!=='object') d.people={};
    d.people[person]={used:true,ts:Date.now()};
    d.person=person;
    d.used=true;
    localStorage.setItem(AI_USED_KEY, JSON.stringify(d));
  }catch(e){
    localStorage.setItem(AI_USED_KEY, JSON.stringify({date:_aiLocalDate(),person:_aiPersonKey(),used:true}));
  }
}
function _aiIsAdmin() { return !!(window._JY_ADMIN_TOKEN); }

