// ═══════════════════════════════════════════════════════════════════════
// [PATCH v3] analyzeJyotishDimension — 改為包裝 analyzeJyotishQuestion
// 以 analyzeJyotishQuestion 為唯一判斷源頭
// ═══════════════════════════════════════════════════════════════════════

function analyzeJyotishDimension(jy, type) {
  if (!jy || !jy.planets || !jy.lagna) {
    return normalizeDimResult('吠陀', { score:50, dir:'mid', confidence:20,
      tags:[], verdict:'資料不足', reason:'吠陀命盤資料不完整' });
  }

  var t = type || 'general';

  // 主引擎：analyzeJyotishQuestion
  var qr = null;
  try {
    qr = (typeof analyzeJyotishQuestion === 'function') ?
      analyzeJyotishQuestion(jy, t, '') : null;
  } catch(e) { qr = null; }

  // 標籤層（保留兼容）
  var tags = [];
  try {
    tags = (typeof analyzeJyotishTags === 'function') ? analyzeJyotishTags(jy, t) : [];
  } catch(e) {}

  // 合併 qr.tags 到 tags
  if (qr && qr.tags && qr.tags.length) {
    qr.tags.forEach(function(qt) {
      // 避免重複
      var exists = tags.some(function(et) { return et.tag === qt.tag; });
      if (!exists) tags.push(qt);
    });
  }

  var score, dir, verdict, reason, confidence, timing;

  if (qr && qr.score) {
    score = qr.score;
    dir = qr.direction === 'positive' ? 'pos' : qr.direction === 'negative' ? 'neg' : 'mid';
    verdict = qr.verdictShort || (dir === 'pos' ? '吠陀格局有力' : dir === 'neg' ? '吠陀有壓力' : '吠陀中性');
    // reason: 取 why 或 evidence 摘要
    var rParts = [];
    if (qr.why1) rParts.push(qr.why1);
    if (qr.why2) rParts.push(qr.why2);
    if (qr.riskPoint && dir !== 'pos') rParts.push('風險：' + qr.riskPoint);
    reason = rParts.join('；');
    if (!reason) {
      reason = tags.filter(function(t){return t.weight>=4;}).slice(0,3).map(function(t){return t.label;}).join('；');
    }
    confidence = qr.confidence || 50;
    // timing from dasha/transit evidence
    var timingEv = (qr.evidence||[]).filter(function(e){return e.layer==='transit'||e.layer==='dasha';});
    timing = timingEv.length >= 3 ? 'short' : timingEv.length >= 1 ? 'mixed' : 'long';
  } else {
    // fallback to tags
    score = (typeof jyotishScoreFromTags === 'function') ? jyotishScoreFromTags(tags) : 50;
    dir = scoreToDir(score);
    verdict = dir === 'pos' ? '吠陀格局有力' : dir === 'neg' ? '吠陀有壓力' : '吠陀中性';
    reason = tags.filter(function(t){return t.weight>=4;}).slice(0,3).map(function(t){return t.label;}).join('；') || '吠陀命盤資料已計算';
    confidence = calcConfidenceFromTags(tags);
    var timingTags = tags.filter(function(t){ return t.category === 'timing'; });
    timing = timingTags.length >= 3 ? 'short' : timingTags.length >= 1 ? 'mixed' : 'long';
  }

  return normalizeDimResult('吠陀', {
    score: score,
    dir: dir,
    confidence: confidence,
    timing: timing,
    tags: tags,
    verdict: verdict,
    reason: reason,
    detail: qr ? ('吠陀問事引擎：' + (qr.yesNoAnswer||'') + '（' + score + '分）') : '議題：' + t
  });
}

