// ── analyzeTarotDimension：塔羅完整維度 ──
function analyzeTarotDimension(tarot, type) {
  try {
    if (!tarot || !tarot.drawn || tarot.drawn.length < 10) return safeMidResult('塔羅', '塔羅尚未抽牌');
    var tags = analyzeTarotTags(tarot.drawn, type);
    var score = tarotScoreFromTags(tags);
    var dir = score>=60?'pos':score<=40?'neg':'mid';

    // 以 buildTarotAnalysisSummary 修正 dir（10規則更準）
    if(buildTarotAnalysisSummary) {
      try {
        var tSum = buildTarotAnalysisSummary(tarot.drawn, type);
        if (tSum && tSum.direction) {
          var _dm = { positive:'pos', reversible_positive:'pos', negative:'neg', reversible_negative:'neg' };
          dir = _dm[tSum.direction] || dir;
        }
      } catch(e2){}
    }

    var conf = (typeof calcConfidenceFromTags === 'function') ? calcConfidenceFromTags(tags) : 50;
    var keyTags = tags.filter(function(t){ return t.weight >= 3; }).slice(0,3);
    var reason = keyTags.map(function(t){ return t.label; }).join('；') || (dir==='pos'?'牌陣整體偏正面':dir==='neg'?'牌陣整體有壓力':'牌陣訊號混合');
    var verdict = dir==='pos'?'塔羅整體偏正面':dir==='neg'?'塔羅整體有壓力':'塔羅訊號混合';
    return { dim:'塔羅', score:score, dir:dir, confidence:conf, timing:'short',
      verdict:verdict, reason:reason, detail:'', tags:tags };
  } catch(e) { return safeMidResult('塔羅', '塔羅分析異常：'+e.message); }
}

