// ══════════════════════════════════════════════════════════════════════
// 🕉️ JYOTISH FUN ZONE — 吠陀占星趣味模組
// 三個模組：今日吠陀訊號 / 星宿互動卡 / 本週行運重點
// 全部吃 analyzeJyotishQuestion / transitImpact / dasha 真實資料
// ══════════════════════════════════════════════════════════════════════

// ═══ 1. 今日吠陀訊號 ═══
function renderJyotishDailySignal() {
  var container = document.getElementById('jy-daily-signal-content');
  if (!container) return;
  if (!S || !S.jyotish) {
    container.innerHTML = '<p class="text-dim">需要先完成基本資料才能計算吠陀每日訊號。</p>';
    return;
  }

  var jy = S.jyotish;
  var type = S.form ? (S.form.type || 'general') : 'general';
  var PZ = { Sun:'太陽', Moon:'月亮', Mars:'火星', Mercury:'水星',
    Jupiter:'木星', Venus:'金星', Saturn:'土星', Rahu:'羅睺', Ketu:'計都' };

  // 取當前 transit + dasha + nakshatra
  var tr = jy.transits || null;
  var md = jy.currentMD || null;
  var ad = jy.currentAD || null;
  var moonNaks = jy.janmaNakshatra || (jy.planets.Moon ? jy.planets.Moon.nakshatra : null);

  // 問事引擎結果
  var qr = null;
  try { qr = (typeof analyzeJyotishQuestion === 'function') ? analyzeJyotishQuestion(jy, type, '') : null; } catch(e) {}

  // 今日主題
  var todayTheme = '';
  if (ad) {
    var adLord = ad.lord;
    var themeMap = {
      Sun: '展現自信與領導力', Moon: '關注內心情緒與家庭', Mars: '積極行動但控制衝動',
      Mercury: '溝通學習與商業思考', Jupiter: '把握機會與貴人運', Venus: '感情互動與審美享受',
      Saturn: '紀律堅持與長期規劃', Rahu: '打破常規但小心幻象', Ketu: '靈性沉澱與放下執著'
    };
    todayTheme = themeMap[adLord] || '穩步前進';
  }

  // 今日避雷
  var todayAvoid = '';
  var negTransit = (jy.transitImpact || []).filter(function(ti) {
    return (ti.planet === 'Saturn' || ti.planet === 'Rahu') && [6,8,12].indexOf(ti.transitBhava) !== -1;
  });
  if (negTransit.length > 0) {
    todayAvoid = '留意' + PZ[negTransit[0].planet] + '在第' + negTransit[0].transitBhava + '宮的壓力，避免衝動決策';
  } else if (jy.sadeSati && jy.sadeSati.active) {
    todayAvoid = '土星七年半期間，日常保持耐心，不與人起正面衝突';
  } else {
    todayAvoid = '沒有特別的避雷項，但記得凡事三思而行';
  }

  // 今日可推進事項
  var todayPush = '';
  var posTransit = (jy.transitImpact || []).filter(function(ti) {
    return ti.planet === 'Jupiter' && [1,2,5,9,10,11].indexOf(ti.transitBhava) !== -1;
  });
  if (posTransit.length > 0) {
    todayPush = '木星正照第' + posTransit[0].transitBhava + '宮，適合拓展、學習或推進重要計劃';
  } else if (qr && qr.direction === 'positive') {
    todayPush = '整體運勢偏好，把握當前節奏推進手上的事';
  } else {
    todayPush = '今天適合穩紮穩打，做好手上的事比追求新目標更實在';
  }

  // 今日情緒調性
  var moonMood = '';
  if (moonNaks) {
    var naksEl = moonNaks.el || '';
    var moodMap = {
      'fire': '精力充沛、行動力強，但容易急躁', 'earth': '踏實穩定、適合處理實務',
      'air': '思維活躍、社交意願高', 'water': '感性細膩、直覺敏銳、適合藝術創作'
    };
    moonMood = moodMap[naksEl] || '情緒穩定，保持平常心即可';
  } else {
    moonMood = '跟著自己的節奏走，不需要特別在意外界干擾';
  }

  var html = '';
  html += '<div style="padding:.6rem;background:rgba(212,175,55,.06);border-radius:8px;margin-bottom:.5rem">';
  html += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">🕉️ 今日吠陀訊號</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>今日主題：</strong>' + todayTheme + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>今日避雷：</strong>' + todayAvoid + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;color:var(--c-gold)"><strong>可推進：</strong>' + todayPush + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>情緒調性：</strong>' + moonMood + '</p>';
  if (md) {
    html += '<p style="font-size:.75rem;margin-top:.4rem;opacity:.6">大運：' + (md.zh || PZ[md.lord] || md.lord) +
      (ad ? ' ／ 副運：' + (ad.zh || PZ[ad.lord] || ad.lord) : '') + '</p>';
  }
  html += '</div>';

  container.innerHTML = html;
}

// ═══ 2. 星宿互動卡 ═══
function renderNakshatraCard() {
  var container = document.getElementById('jy-nakshatra-card-content');
  if (!container) return;
  if (!S || !S.jyotish || !S.jyotish.planets || !S.jyotish.planets.Moon) {
    container.innerHTML = '<p class="text-dim">需要先完成基本資料才能顯示星宿互動卡。</p>';
    return;
  }

  var moonP = S.jyotish.planets.Moon;
  var naks = moonP.nakshatra;
  if (!naks) { container.innerHTML = '<p class="text-dim">星宿資料未產生。</p>'; return; }

  var _lordZh = { Ketu:'計都', Venus:'金星', Sun:'太陽', Moon:'月亮', Mars:'火星',
    Rahu:'羅睺', Jupiter:'木星', Saturn:'土星', Mercury:'水星' };

  // 星宿特質對照
  var naksTraits = {
    'Ashwini': { style:'快速行動型', goodAction:'果斷出擊、嘗試新事物', avoidMode:'拖延不決、過度謹慎', lucky:'清晨運動或出門' },
    'Bharani': { style:'深度投入型', goodAction:'專注完成一件重要的事', avoidMode:'同時處理太多事、表面社交', lucky:'整理舊物或斷捨離' },
    'Krittika': { style:'直率犀利型', goodAction:'說出真心話、面對問題', avoidMode:'彎彎繞繞、逃避正面溝通', lucky:'吃辛辣食物或享受陽光' },
    'Rohini': { style:'享受生活型', goodAction:'美食、藝術、品味提升', avoidMode:'過度節省、壓抑享受', lucky:'穿柔和色彩的衣服' },
    'Mrigashira': { style:'好奇探索型', goodAction:'研究新知、旅行或換環境', avoidMode:'固守成見、拒絕嘗試', lucky:'散步或接觸自然' },
    'Ardra': { style:'情緒風暴型', goodAction:'面對和釋放情緒、寫日記', avoidMode:'壓抑情緒、假裝沒事', lucky:'聽音樂或看一場觸動內心的電影' },
    'Punarvasu': { style:'回歸初心型', goodAction:'修復關係、重新開始某件事', avoidMode:'一直往前衝不回頭看', lucky:'回到熟悉的地方充電' },
    'Pushya': { style:'照顧滋養型', goodAction:'幫助他人、照顧家人', avoidMode:'只顧自己、忽略身邊的人', lucky:'做一頓飯或泡一杯茶' },
    'Ashlesha': { style:'直覺洞察型', goodAction:'信任直覺、深度思考', avoidMode:'輕信表面訊息、衝動決策', lucky:'冥想或獨處片刻' },
    'Magha': { style:'王者氣場型', goodAction:'展現領導力、承擔責任', avoidMode:'畏縮退讓、放棄主導權', lucky:'穿正式或有氣場的衣服' },
    'Purva Phalguni': { style:'歡樂社交型', goodAction:'聚會、約會、放鬆享樂', avoidMode:'宅在家一整天不動', lucky:'笑、唱歌或跳舞' },
    'Uttara Phalguni': { style:'穩健承擔型', goodAction:'簽約、承諾、長期規劃', avoidMode:'臨時改主意、反覆不定', lucky:'跟值得信賴的人共事' },
    'Hasta': { style:'手作創造型', goodAction:'動手做東西、整理環境', avoidMode:'光說不練、空想', lucky:'用雙手創造些什麼' },
    'Chitra': { style:'藝術設計型', goodAction:'美化環境、設計規劃', avoidMode:'敷衍了事、忽略細節', lucky:'逛美術館或穿搭配色' },
    'Swati': { style:'自由靈活型', goodAction:'保持彈性、接受變化', avoidMode:'固執己見、排斥新選擇', lucky:'讓風吹過臉、到開闊的地方走走' },
    'Vishakha': { style:'目標導向型', goodAction:'鎖定一個目標全力以赴', avoidMode:'三心二意、分散精力', lucky:'列一張行動清單並執行' },
    'Anuradha': { style:'深度連結型', goodAction:'深入交流、維護友誼', avoidMode:'表面寒暄、避免深層對話', lucky:'打一通電話給重要的人' },
    'Jyeshtha': { style:'權威智慧型', goodAction:'分享經驗、指導他人', avoidMode:'凡事自己扛、不願求助', lucky:'閱讀或傳授知識' },
    'Moola': { style:'根本探索型', goodAction:'探索真相、面對根源問題', avoidMode:'只處理表面症狀', lucky:'深呼吸三次然後做決定' },
    'Purva Ashadha': { style:'信心充沛型', goodAction:'發起新計劃、激勵他人', avoidMode:'懷疑自己、猶豫不前', lucky:'接觸水（游泳、泡澡）' },
    'Uttara Ashadha': { style:'堅毅持久型', goodAction:'堅持到底、不輕言放棄', avoidMode:'半途而廢、被困難嚇退', lucky:'完成一件拖延已久的事' },
    'Shravana': { style:'傾聽學習型', goodAction:'聽講座、學新東西、傾聽他人', avoidMode:'只說不聽、自說自話', lucky:'戴上耳機聽一集好的 podcast' },
    'Dhanishta': { style:'節奏掌控型', goodAction:'找到自己的節奏、音樂療癒', avoidMode:'被別人的節奏帶著走', lucky:'聽一首喜歡的歌打打節拍' },
    'Shatabhisha': { style:'獨立療癒型', goodAction:'自我修復、獨立思考', avoidMode:'依賴他人做決定', lucky:'泡一杯花草茶靜坐片刻' },
    'Purva Bhadrapada': { style:'理想主義型', goodAction:'追求有意義的事、公益行動', avoidMode:'只追求物質利益', lucky:'做一件利他的小事' },
    'Uttara Bhadrapada': { style:'深層寧靜型', goodAction:'靜心冥想、長遠規劃', avoidMode:'浮躁急進、追求短期快感', lucky:'在安靜的地方待半小時' },
    'Revati': { style:'慈悲關懷型', goodAction:'表達同理心、照顧弱勢', avoidMode:'冷漠旁觀、自掃門前雪', lucky:'對陌生人微笑或幫助小動物' }
  };

  var trait = naksTraits[naks.en] || { style:'平衡穩健型', goodAction:'跟著感覺走', avoidMode:'過度焦慮', lucky:'做自己喜歡的事' };

  var html = '';
  html += '<div style="padding:.6rem;background:rgba(148,163,184,.06);border-radius:8px">';
  html += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">⭐ 你的星宿互動卡</p>';
  html += '<p style="font-size:.85rem;margin:.2rem 0"><strong>命宿：</strong>' + naks.zh + '（' + naks.en + '）・星宿主星：' + (_lordZh[moonP.naksLord] || moonP.naksLord) + '</p>';
  html += '<p style="font-size:.85rem;margin:.2rem 0"><strong>你的類型：</strong>' + trait.style + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;color:var(--c-gold)"><strong>適合的互動方式：</strong>' + trait.goodAction + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;color:#fca5a5"><strong>避免的相處模式：</strong>' + trait.avoidMode + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>幸運行動：</strong>' + trait.lucky + '</p>';
  html += '</div>';

  container.innerHTML = html;
}

// ═══ 3. 本週行運重點 ═══
function renderWeeklyTransitFocus() {
  var container = document.getElementById('jy-weekly-transit-content');
  if (!container) return;
  if (!S || !S.jyotish) {
    container.innerHTML = '<p class="text-dim">需要先完成基本資料才能計算本週行運重點。</p>';
    return;
  }

  var jy = S.jyotish;
  var PZ = { Sun:'太陽', Moon:'月亮', Mars:'火星', Mercury:'水星',
    Jupiter:'木星', Venus:'金星', Saturn:'土星', Rahu:'羅睺', Ketu:'計都' };

  // 用 transitImpact 對應三大議題
  var topicMap = {
    love: { houses:[5,7], label:'感情' },
    career: { houses:[6,10], label:'事業' },
    wealth: { houses:[2,11], label:'財運' }
  };

  var weeklyHtml = '';
  weeklyHtml += '<div style="padding:.6rem;background:rgba(74,222,128,.04);border-radius:8px">';
  weeklyHtml += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.5rem;font-size:.92rem">📅 本週行運重點</p>';

  var hasContent = false;
  ['love', 'career', 'wealth'].forEach(function(topic) {
    var cfg = topicMap[topic];
    var relevantTransits = (jy.transitImpact || []).filter(function(ti) {
      return ['Jupiter','Saturn','Rahu','Ketu'].indexOf(ti.planet) !== -1 &&
        cfg.houses.indexOf(ti.transitBhava) !== -1;
    });

    // 用 analyzeJyotishQuestion 做快速判斷
    var qr = null;
    try { qr = (typeof analyzeJyotishQuestion === 'function') ? analyzeJyotishQuestion(jy, topic, '') : null; } catch(e) {}

    var icon = topic === 'love' ? '💕' : topic === 'career' ? '💼' : '💰';
    var statusColor, statusText;

    if (qr && qr.score) {
      if (qr.score >= 60) { statusColor = '#4ade80'; statusText = '有動靜（偏利）'; }
      else if (qr.score <= 40) { statusColor = '#f87171'; statusText = '有壓力（需注意）'; }
      else { statusColor = '#fbbf24'; statusText = '平穩（觀望）'; }
    } else {
      statusColor = 'var(--c-text-dim)'; statusText = '平穩';
    }

    weeklyHtml += '<div style="display:flex;align-items:center;gap:8px;margin:.3rem 0;padding:.3rem;border-radius:4px;background:rgba(255,255,255,.02)">';
    weeklyHtml += '<span style="font-size:1rem">' + icon + '</span>';
    weeklyHtml += '<span style="font-size:.85rem;min-width:40px">' + cfg.label + '</span>';
    weeklyHtml += '<span style="font-size:.82rem;color:' + statusColor + ';font-weight:600">' + statusText + '</span>';

    if (relevantTransits.length > 0) {
      var trText = relevantTransits.map(function(ti) {
        return PZ[ti.planet] + '在第' + ti.transitBhava + '宮';
      }).join('、');
      weeklyHtml += '<span style="font-size:.72rem;opacity:.6;margin-left:auto">' + trText + '</span>';
      hasContent = true;
    } else if (qr && qr.verdictShort) {
      weeklyHtml += '<span style="font-size:.72rem;opacity:.6;margin-left:auto">' + qr.verdictShort + '</span>';
      hasContent = true;
    }

    weeklyHtml += '</div>';
  });

  if (!hasContent) {
    weeklyHtml += '<p style="font-size:.8rem;opacity:.6;margin-top:.3rem">本週行運無特別重大變動，維持原有步調即可。</p>';
  }

  // 提示 Sade Sati
  if (jy.sadeSati && jy.sadeSati.active) {
    weeklyHtml += '<p style="font-size:.78rem;color:#fca5a5;margin-top:.4rem">⚠ 土星七年半進行中，整體壓力水位偏高。</p>';
  }

  weeklyHtml += '</div>';
  container.innerHTML = weeklyHtml;
}

// ═══ 統一觸發：renderJyotishFunZone ═══
function renderJyotishFunZone() {
  try { renderJyotishDailySignal(); } catch(e) { console.warn('jyDailySignal err:', e); }
  try { renderNakshatraCard(); } catch(e) { console.warn('naksCard err:', e); }
  try { renderWeeklyTransitFocus(); } catch(e) { console.warn('weeklyTransit err:', e); }
}

