// ══════════════════════════════════════════════════════════════════════
// 📛 NAME FUN ZONE — 姓名學趣味模組
// 三個模組：名字氣場卡 / 人際風格卡 / 能量傾向卡
// 全部吃 analyzeNameQuestion / nameResult / zodiacNameResult 真實資料
// ══════════════════════════════════════════════════════════════════════

// ═══ 1. 今日名字氣場卡 ═══
function renderNameAuraCard() {
  var container = document.getElementById('name-aura-card-content');
  if (!container) return;
  if (!S || !S.form || !S.form.name || S.form.name.length < 2) {
    container.innerHTML = '<p class="text-dim">需要先輸入姓名才能產生氣場卡。</p>';
    return;
  }

  var nr = S.nameResult || null;
  var zr = S.zodiacNameResult || null;
  var type = S.form ? (S.form.type || 'general') : 'general';

  var qr = null;
  try { qr = (typeof analyzeNameQuestion === 'function') ? analyzeNameQuestion(nr, zr, { type:type, bazi:S.bazi||null }) : null; } catch(e) {}

  var mainTone = '平穩';
  var stuckPoint = '無明顯卡點';
  var actionStyle = '順勢而為';

  if (qr) {
    if (qr.score >= 65) { mainTone = '助力型 — 名字能量今天幫你加分'; stuckPoint = '不要太依賴好運，該做的功課還是要做'; actionStyle = '積極主動、大膽表達'; }
    else if (qr.score >= 50) { mainTone = '平穩型 — 名字不拖後腿也不特別推進'; stuckPoint = '中性時期最容易懈怠，保持專注'; actionStyle = '穩紮穩打、不急不緩'; }
    else if (qr.score >= 35) { mainTone = '拉扯型 — 名字能量有些內耗'; stuckPoint = qr.riskPoint || '小心過度內耗或溝通失誤'; actionStyle = '謹慎行事、先想後做'; }
    else { mainTone = '壓力型 — 名字能量今天偏沉重'; stuckPoint = qr.riskPoint || '避免重大決策、先穩住心態'; actionStyle = '低調保守、減少衝突'; }
  }

  var html = '';
  html += '<div style="padding:.6rem;background:rgba(212,175,55,.06);border-radius:8px">';
  html += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">📛 今日名字氣場卡</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>今日主調：</strong>' + mainTone + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>易卡點：</strong>' + stuckPoint + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;color:var(--c-gold)"><strong>行動風格：</strong>' + actionStyle + '</p>';
  if (nr && nr.sanCai) html += '<p style="font-size:.75rem;margin-top:.4rem;opacity:.6">三才：' + nr.sanCai.join('→') + '（' + (nr.sanCaiLevel||'') + '）</p>';
  html += '</div>';
  container.innerHTML = html;
}

// ═══ 2. 名字人際風格卡 ═══
function renderNameSocialCard() {
  var container = document.getElementById('name-social-card-content');
  if (!container) return;
  if (!S || !S.form || !S.form.name || S.form.name.length < 2) {
    container.innerHTML = '<p class="text-dim">需要先輸入姓名才能產生人際風格卡。</p>';
    return;
  }

  var nr = S.nameResult || null;
  var zr = S.zodiacNameResult || null;

  var feeling = '穩定中性';
  var commTip = '正常溝通即可';
  var avoidMode = '無特別避雷';

  // 用外格判斷人際
  if (nr && nr.waiGe && nr.waiGe.fortune) {
    var waiLevel = nr.waiGe.fortune.level;
    if (waiLevel === '大吉' || waiLevel === '吉') {
      feeling = '親和力強、容易讓人卸下心防';
      commTip = '適合主動邀約、談合作、拓展人脈';
      avoidMode = '別因為太好說話而讓人得寸進尺';
    } else if (waiLevel === '凶') {
      feeling = '稍有距離感、不容易被快速信任';
      commTip = '重要對話先打草稿，避免話中帶刺';
      avoidMode = '避免在群組中公開批評，容易被放大';
    }
  }

  // 生肖衝突字根影響
  if (zr) {
    if (zr.isSacrifice) {
      feeling = '你容易被人感覺「什麼都扛」，表面堅強內心疲憊';
      avoidMode = '今天不要主動攬事，學會說「我需要想想」';
    } else if (zr.isSnakePigClash) {
      feeling = '磁場有些混亂，容易吸引到立場不同的人';
      avoidMode = '避免跟不熟的人聊敏感話題';
    }
  }

  var html = '';
  html += '<div style="padding:.6rem;background:rgba(148,163,184,.06);border-radius:8px">';
  html += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">🤝 名字人際風格卡</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0"><strong>給人的感受：</strong>' + feeling + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;color:var(--c-gold)"><strong>溝通建議：</strong>' + commTip + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;color:#fca5a5"><strong>避雷：</strong>' + avoidMode + '</p>';
  html += '</div>';
  container.innerHTML = html;
}

// ═══ 3. 名字能量傾向卡 ═══
function renderNameEnergyCard() {
  var container = document.getElementById('name-energy-card-content');
  if (!container) return;
  if (!S || !S.form || !S.form.name || S.form.name.length < 2) {
    container.innerHTML = '<p class="text-dim">需要先輸入姓名才能產生能量傾向卡。</p>';
    return;
  }

  var nr = S.nameResult || null;
  var zr = S.zodiacNameResult || null;

  // 能量分類：衝刺/守成/內耗/穩定/親和
  var energyType = '穩定型';
  var energyDesc = '你的名字能量偏中性，不特別衝也不特別守。';
  var energyAdvice = '跟著自己的節奏走就好。';

  if (nr) {
    var renLevel = (nr.renGe && nr.renGe.fortune) ? nr.renGe.fortune.level : '平';
    var zongLevel = (nr.zongGe && nr.zongGe.fortune) ? nr.zongGe.fortune.level : '平';
    var scLevel = nr.sanCaiLevel || '平';
    var renEl = nr.renGe ? nr.renGe.el : '';

    // 衝刺型：人格吉 + 火/木
    if ((renLevel === '大吉' || renLevel === '吉') && (renEl === '火' || renEl === '木')) {
      energyType = '衝刺型 🔥';
      energyDesc = '你的名字能量帶有行動力和開創性，適合主動出擊、開拓新局面。';
      energyAdvice = '善用衝勁，但記得煞車機制，衝太快容易翻車。';
    }
    // 守成型：總格吉 + 土/金
    else if ((zongLevel === '大吉' || zongLevel === '吉') && (renEl === '土' || renEl === '金')) {
      energyType = '守成型 🏔️';
      energyDesc = '你的名字能量偏穩健紮實，適合長期累積和穩步前進。';
      energyAdvice = '你的優勢在耐力和可靠度，不需要跟別人比速度。';
    }
    // 內耗型：三才凶 or 犧牲格
    else if (scLevel === '凶' || (zr && zr.isSacrifice)) {
      energyType = '內耗型 💔';
      energyDesc = '你的名字能量容易讓壓力往內積累，外表看不出來但自己很累。';
      energyAdvice = '學會適時釋放壓力，不要什麼都往自己身上扛。運動、寫日記、跟信任的人傾訴都有幫助。';
    }
    // 親和型：地格/外格吉 + 水
    else if (nr.diGe && nr.diGe.fortune && (nr.diGe.fortune.level === '大吉' || nr.diGe.fortune.level === '吉') && renEl === '水') {
      energyType = '親和型 💧';
      energyDesc = '你的名字能量帶有柔和和包容性，天生容易讓人放鬆。';
      energyAdvice = '你的武器是人緣和溝通力，好好發揮。';
    }
    // 穩定型
    else if (scLevel.includes('吉')) {
      energyType = '穩定型 ⚖️';
      energyDesc = '你的名字能量平衡穩固，三才流通良好，基底紮實。';
      energyAdvice = '穩定是你最大的本錢，在別人動盪的時候你反而最有優勢。';
    }
  }

  var html = '';
  html += '<div style="padding:.6rem;background:rgba(74,222,128,.04);border-radius:8px">';
  html += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">⚡ 名字能量傾向卡</p>';
  html += '<p style="font-size:.92rem;margin:.3rem 0;font-weight:700;color:var(--c-gold)">' + energyType + '</p>';
  html += '<p style="font-size:.85rem;margin:.3rem 0;line-height:1.6">' + energyDesc + '</p>';
  html += '<p style="font-size:.85rem;margin:.4rem 0;color:var(--c-gold)">💡 ' + energyAdvice + '</p>';
  html += '</div>';
  container.innerHTML = html;
}

// ═══ 統一觸發 ═══
function renderNameFunZone() {
  try { renderNameAuraCard(); } catch(e) { console.warn('nameAura err:', e); }
  try { renderNameSocialCard(); } catch(e) { console.warn('nameSocial err:', e); }
  try { renderNameEnergyCard(); } catch(e) { console.warn('nameEnergy err:', e); }
}

