// ══════════════════════════════════════════════════════════════════════
// ♈ NATAL FUN ZONE — 西方星盤趣味模組
// 三個模組：主調卡 / 互動提醒卡 / 行動風格卡
// ══════════════════════════════════════════════════════════════════════

function renderNatalMoodCard() {
  var c = document.getElementById('natal-mood-card-content');
  if (!c) return;
  if (!S || !S.natal) { c.innerHTML = '<p class="text-dim">需要先完成基本資料才能產生星盤主調卡。</p>'; return; }
  var type = S.form ? (S.form.type||'general') : 'general';
  var qr = null;
  try { qr = (typeof analyzeNatalQuestion==='function') ? analyzeNatalQuestion(S.natal, type, '') : null; } catch(e) {}
  var mood = '穩定', tip = '順勢而為';
  if (qr) {
    if (qr.score >= 65) { mood = '積極有力 — 星盤今天給你撐腰'; tip = '適合主動出擊、做決定'; }
    else if (qr.score >= 50) { mood = '平穩中性 — 不急不躁最好'; tip = '穩紮穩打、不需要冒險'; }
    else if (qr.score >= 35) { mood = '有點拉扯 — 內外不太一致'; tip = '重要對話先打草稿、別衝動'; }
    else { mood = '偏沉重 — 壓力感較明顯'; tip = '低調保守、照顧好自己的能量'; }
  }
  var h = '<div style="padding:.6rem;background:rgba(212,175,55,.06);border-radius:8px">';
  h += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">♈ 今日星盤主調卡</p>';
  h += '<p style="font-size:.85rem;margin:.3rem 0"><strong>今日調性：</strong>' + mood + '</p>';
  h += '<p style="font-size:.85rem;margin:.3rem 0;color:var(--c-gold)"><strong>建議：</strong>' + tip + '</p>';
  if (S.natal.ascSign) h += '<p style="font-size:.75rem;margin-top:.4rem;opacity:.6">上升' + S.natal.ascSign.name + ' ☉' + S.natal.planets['太陽'].sign + ' ☽' + S.natal.planets['月亮'].sign + '</p>';
  h += '</div>';
  c.innerHTML = h;
}

function renderNatalInteractionCard() {
  var c = document.getElementById('natal-interaction-card-content');
  if (!c) return;
  if (!S || !S.natal || !S.natal.planets) { c.innerHTML = '<p class="text-dim">需要基本資料。</p>'; return; }
  var np = S.natal.planets;
  var smooth = '一般溝通即可', mine = '無特別地雷';
  var venH = np['金星'] ? np['金星'].house : 0;
  var merH = np['水星'] ? np['水星'].house : 0;
  var moonH = np['月亮'] ? np['月亮'].house : 0;
  if ([3,7,11].indexOf(venH)!==-1 || [3,7,11].indexOf(merH)!==-1) smooth = '今天你的溝通能量好，適合主動聊天、提案、談合作';
  else if ([12,8].indexOf(merH)!==-1) smooth = '表達上偏含蓄，重要訊息建議用文字確認';
  if ([6,8,12].indexOf(moonH)!==-1) mine = '情緒敏感期，避免在疲累時做重要溝通';
  else if ([1,5].indexOf(moonH)!==-1) mine = '情緒外放，小心話講太直得罪人';
  var h = '<div style="padding:.6rem;background:rgba(148,163,184,.06);border-radius:8px">';
  h += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">💬 星盤互動提醒卡</p>';
  h += '<p style="font-size:.85rem;margin:.3rem 0;color:var(--c-gold)"><strong>容易順的：</strong>' + smooth + '</p>';
  h += '<p style="font-size:.85rem;margin:.3rem 0;color:#fca5a5"><strong>容易踩雷的：</strong>' + mine + '</p>';
  h += '</div>';
  c.innerHTML = h;
}

function renderNatalActionCard() {
  var c = document.getElementById('natal-action-card-content');
  if (!c) return;
  if (!S || !S.natal || !S.natal.planets) { c.innerHTML = '<p class="text-dim">需要基本資料。</p>'; return; }
  var np = S.natal.planets;
  var style = '穩定型 ⚖️', desc = '跟著節奏走', advice = '不急不緩最適合你';
  var sunH = np['太陽'] ? np['太陽'].house : 0;
  var marsH = np['火星'] ? np['火星'].house : 0;
  var satH = np['土星'] ? np['土星'].house : 0;
  if ([1,10].indexOf(sunH)!==-1 && [1,5,10].indexOf(marsH)!==-1) {
    style = '衝刺型 🔥'; desc = '太陽和火星都在有力位置'; advice = '今天適合行動、決策、推進重要項目';
  } else if ([6,8,12].indexOf(marsH)!==-1 || [1,4,7,10].indexOf(satH)!==-1) {
    style = '收斂型 🏔️'; desc = '行動力被壓制，但紀律是你的武器'; advice = '今天適合規劃、整理、做長期佈局';
  } else if ([3,7,11].indexOf(sunH)!==-1) {
    style = '協調型 🤝'; desc = '太陽在社交位置'; advice = '今天適合溝通、協商、建立關係';
  } else if ([9,12].indexOf(sunH)!==-1) {
    style = '觀察型 👁️'; desc = '太陽在思考位置'; advice = '今天適合學習、反思、收集資訊';
  }
  var h = '<div style="padding:.6rem;background:rgba(74,222,128,.04);border-radius:8px">';
  h += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.4rem;font-size:.92rem">⚡ 星盤行動風格卡</p>';
  h += '<p style="font-size:.92rem;margin:.3rem 0;font-weight:700;color:var(--c-gold)">' + style + '</p>';
  h += '<p style="font-size:.85rem;margin:.3rem 0">' + desc + '</p>';
  h += '<p style="font-size:.85rem;margin:.4rem 0;color:var(--c-gold)">💡 ' + advice + '</p>';
  h += '</div>';
  c.innerHTML = h;
}

function renderNatalFunZone() {
  try { renderNatalMoodCard(); } catch(e) {}
  try { renderNatalInteractionCard(); } catch(e) {}
  try { renderNatalActionCard(); } catch(e) {}
}

