// ══════════════════════════════════════════════════════════════════════
// ✦ ZiWei Question Engine v2 — 紫微可獨立答題 / 主渲染 / 趣味區共用
// ══════════════════════════════════════════════════════════════════════
(function(){
  var ZW_GOOD = ['紫微','天府','天同','天梁','天相','太陽','太陰','左輔','右弼','文昌','文曲','天魁','天鉞','祿存'];
  var ZW_RISK = ['擎羊','陀羅','火星','鈴星','地劫','地空','天刑'];
  var ZW_MAJOR_WEIGHT = {
    '紫微':5,'天府':5,'天相':4,'天梁':4,'太陽':4,'太陰':4,'武曲':4,
    '天機':3,'天同':3,'廉貞':3,'貪狼':3,'巨門':2,'七殺':2,'破軍':2
  };
  var ZW_DOMAIN = {
    love:{main:2, label:'感情', palace:'夫妻宮', triad:[2,6,10,8], focusStars:['太陰','貪狼','天喜','紅鸞','文曲']},
    career:{main:8, label:'事業', palace:'官祿宮', triad:[8,0,4,2], focusStars:['紫微','天相','武曲','天府','七殺','破軍']},
    wealth:{main:4, label:'財運', palace:'財帛宮', triad:[4,8,0,10], focusStars:['武曲','太陰','天府','祿存','化祿']},
    health:{main:5, label:'健康', palace:'疾厄宮', triad:[5,11,3,1], focusStars:['天梁','太陰','火星','鈴星','化忌']},
    relationship:{main:7, label:'人際', palace:'交友宮', triad:[7,1,5,9], focusStars:['天相','天同','巨門','文昌','文曲']},
    family:{main:9, label:'家庭', palace:'田宅宮', triad:[9,3,7,5], focusStars:['太陰','天府','巨門','左輔','右弼']},
    general:{main:0, label:'整體', palace:'命宮', triad:[0,4,8,6], focusStars:['紫微','天府','太陽','太陰','天相']}
  };
  var ZW_TIMING_MAP = {
    love:'先看夫妻宮，再看今年夫妻/遷移/福德連動',
    career:'先看官祿宮，再看財帛與命宮能否接住',
    wealth:'先看財帛宮，再看官祿/田宅能否落袋',
    health:'先看疾厄宮，再看福德/父母宮是否加重壓力',
    relationship:'先看交友宮，再看兄弟/遷移宮互動',
    family:'先看田宅宮，再看子女/父母宮是否牽動',
    general:'先看命宮，再看官祿/財帛/遷移三方四正'
  };

  function __zwSafeArr(v){ return Array.isArray(v) ? v : []; }
  function __zwCfg(type){ return ZW_DOMAIN[type] || ZW_DOMAIN.general; }
  function __zwDirFromScore(score){ return score>=64 ? 'positive' : score<=42 ? 'negative' : 'neutral'; }
  function __zwAnswerFromScore(score, cfg){
    if(score>=78) return '可以主動推進，紫微盤對這題是明顯支持。';
    if(score>=64) return '整體偏可行，但要挑對時間點，不宜亂衝。';
    if(score>=52) return '有機會，但不是順風局，要靠策略與節奏。';
    if(score>=42) return '目前拉扯偏重，先處理卡點再推進。';
    return cfg.label+'這題暫時不利，硬推容易先受傷。';
  }
  function __zwScoreStar(s){
    if(!s) return 0;
    var n=s.name||'';
    var v=ZW_MAJOR_WEIGHT[n]||0;
    if(s.type==='major') v += 1;
    if(ZW_GOOD.indexOf(n)!==-1) v += 1;
    if(ZW_RISK.indexOf(n)!==-1) v -= 3;
    if(s.hua==='化祿') v += 4;
    else if(s.hua==='化權') v += 2;
    else if(s.hua==='化科') v += 2;
    else if(s.hua==='化忌') v -= 5;
    var br = s.bright || '';
    if(br==='廟') v += 2;
    else if(br==='旺') v += 1;
    else if(br==='陷' || br==='落陷' || br==='不得') v -= 2;
    return v;
  }
  function __zwStarsOf(p){ return p && Array.isArray(p.stars) ? p.stars : []; }
  function __zwPalaceInfo(zw, idx){
    var p = zw && zw.palaces ? zw.palaces[idx] : null;
    var stars = __zwStarsOf(p);
    var majors = stars.filter(function(s){ return s.type==='major'; });
    var goods = stars.filter(function(s){ return ZW_GOOD.indexOf(s.name)!==-1 || ['化祿','化權','化科'].indexOf(s.hua)!==-1; });
    var risks = stars.filter(function(s){ return ZW_RISK.indexOf(s.name)!==-1 || s.hua==='化忌'; });
    var score = stars.reduce(function(sum,s){ return sum + __zwScoreStar(s); }, 0);
    return { palace:p, stars:stars, majors:majors, goods:goods, risks:risks, score:score };
  }
  function __zwFindCurrentDx(zw){
    if(!zw || !zw.daXian) return null;
    return zw.daXian.find(function(d){ return d.isCurrent; }) || null;
  }
  function __zwFindCurrentLn(zw){
    var year = new Date().getFullYear();
    try{
      var dx = __zwFindCurrentDx(zw);
      if(dx && Array.isArray(dx.liuNian)) return dx.liuNian.find(function(y){ return y.year===year; }) || null;
      if(zw && typeof zw.getLiuNianZw==='function') return zw.getLiuNianZw(year) || null;
    }catch(e){}
    return null;
  }
  function __zwFormatReasons(arr){
    return arr.filter(Boolean).slice(0,3).join('；');
  }
  function __zwTimingText(zw, type, focusInfo, dx, ln){
    var year = new Date().getFullYear();
    var parts = [];
    if(dx) parts.push('十年主軸在'+dx.palaceName+'大限');
    if(ln && ln.mingPalace) parts.push(year+'年流年命宮走'+ln.mingPalace);
    if(focusInfo.risks.length && !focusInfo.goods.length) parts.push('先解'+(focusInfo.risks[0].name||focusInfo.risks[0].hua||'煞忌')+'再談推進');
    if(focusInfo.goods.length && !focusInfo.risks.length) parts.push('先天宮位乾淨，時機比一般盤更好抓');
    if(!parts.length) parts.push(ZW_TIMING_MAP[type] || ZW_TIMING_MAP.general);
    return parts.join('，');
  }
  function __zwActionByType(type, dir, focusInfo){
    var risk = focusInfo.risks[0];
    var good = focusInfo.goods[0] || focusInfo.majors[0];
    var map = {
      love: {
        pos:['可以主動製造互動，但不要一次逼對方表態','先看對方回應速度與穩定度，再決定要不要加碼'],
        mid:['先清掉舊情緒與猜測，關係才會往前走','這題不是沒有機會，而是怕你急在對方前面'],
        neg:['先停掉情緒硬衝，尤其避免在不安時逼問答案','這題的卡點多半在信任、距離或現實條件']
      },
      career: {
        pos:['可以爭取資源、談職務、提方案，這題有主動權','先把成果量化，紫微盤比較吃實績而不是空話'],
        mid:['先補流程、能力或人脈缺口，再去談位階','這題可以做，但要先把風險控住'],
        neg:['先守現職或先避開正面衝突，不適合硬碰硬','眼下比較像制度壓力，不是單靠努力就能解']
      },
      wealth: {
        pos:['有財路，但要重視落袋，不要只看帳面數字','先做穩定收入或可控標的，偏財可以小試不要重壓'],
        mid:['財運有波動，先守現金流比追高重要','把漏財點抓出來，常比找新財路更有效'],
        neg:['先止損、先守本，這題不是衝收益的時間','有忌煞時，越想快賺越容易反被套住']
      },
      health: {
        pos:['能調回來，但前提是你要規律，不是靠一次補救','先處理作息與壓力，效果會比臨時進補更直接'],
        mid:['健康不是大凶，但已經在提醒你不要再透支','把會反覆發作的習慣找出來，比看單次好壞更重要'],
        neg:['先休息、先檢查、先降低負荷，別再硬撐','這題多半不是突然出事，而是累積太久的訊號']
      },
      relationship: {
        pos:['人際可用，但要分層，不是每個人都值得深交','先找能交換資源的人，而不是只找熱鬧'],
        mid:['互動可維持，但邊界要先講清楚','這題最怕的是表面和氣、背後失衡'],
        neg:['先減少無效社交與情緒性對話','你現在更需要篩選圈子，不是拼命擴大圈子']
      },
      family: {
        pos:['家庭面可談、可修、可整合，但要有人先讓一步','如果要處理房產或家庭分工，現在比拖著好'],
        mid:['家庭問題不是爆點，而是長期累積的小結','先處理日常分工與情緒，不要一開始就談結論'],
        neg:['先降低正面衝突，尤其別在情緒上頭時硬談','這題多半有舊帳，想快解通常只會更亂']
      },
      general: {
        pos:['可以推進你最在意的那件事，但仍要抓主次','先做最有把握的一步，紫微盤不支持亂槍打鳥'],
        mid:['整體可動，但不是全面開戰的格局','先穩核心，再處理旁支，勝率會高很多'],
        neg:['整體先守，再選一個最重要的點處理','你現在最怕的是同時處理太多，結果每個都卡']
      }
    };
    var t = map[type] || map.general;
    var res = dir==='positive' ? t.pos : dir==='negative' ? t.neg : t.mid;
    if(risk) res = [res[0], '目前主要卡點在「'+(risk.name || risk.hua || '煞忌')+'」，先處理這個再談擴張'];
    else if(good) res = [res[0], '目前最能借力的是「'+(good.name || good.hua || '吉星')+'」這股能量'];
    return res;
  }
  function __zwConfidence(zw, focusInfo, dx, ln){
    var conf = 48;
    conf += Math.min(20, focusInfo.majors.length * 5);
    conf += Math.min(10, focusInfo.goods.length * 2);
    conf += Math.min(8, focusInfo.risks.length * 2);
    if(dx) conf += 6;
    if(ln) conf += 6;
    return Math.max(35, Math.min(92, conf));
  }
  function __zwCompositeScore(zw, type){
    var cfg = __zwCfg(type);
    var focusIdxs = cfg.triad || [cfg.main];
    var parts = focusIdxs.map(function(idx){ return __zwPalaceInfo(zw, idx); });
    var focus = parts[0] || { score:0, goods:[], risks:[], majors:[] };
    var triadScore = parts.reduce(function(sum,p,ix){ return sum + (ix===0 ? p.score*1.2 : p.score*0.6); }, 0);
    var dx = __zwFindCurrentDx(zw);
    var ln = __zwFindCurrentLn(zw);
    var score = 50 + triadScore;
    if(dx){
      if(dx.level && /大吉|中吉/.test(dx.level)) score += 9;
      else if(dx.level && /小吉/.test(dx.level)) score += 5;
      else if(dx.level && /偏弱|低迷|凶/.test(dx.level)) score -= 9;
      if(Array.isArray(dx.hua)){
        dx.hua.forEach(function(h){
          if((cfg.triad||[]).indexOf((zw.palaces||[]).findIndex(function(p){ return p && p.name===h.palace; }))!==-1){
            if(h.hua==='化祿') score += 4;
            else if(h.hua==='化權' || h.hua==='化科') score += 2;
            else if(h.hua==='化忌') score -= 5;
          }
        });
      }
    }
    if(ln){
      if(typeof ln.score === 'number') score += Math.max(-8, Math.min(8, ln.score*2));
      if(Array.isArray(ln.hua || ln.siHua)){
        (ln.hua || ln.siHua).forEach(function(h){
          if(h.hua==='化祿') score += 3;
          else if(h.hua==='化權' || h.hua==='化科') score += 1;
          else if(h.hua==='化忌') score -= 4;
        });
      }
    }
    return { score:Math.max(8, Math.min(95, Math.round(score))), focus:focus, parts:parts, dx:dx, ln:ln, cfg:cfg };
  }

  window.analyzeZiweiQuestion = function(zw, type, userQuestion){
    if(!zw || !zw.palaces || !zw.palaces.length){
      return { yesNoAnswer:'紫微資料不足，無法判斷。', direction:'neutral', score:50, confidence:20,
        why1:'缺少紫微盤資料', why2:'', why3:'', riskPoint:'', action1:'', action2:'', strategies:[], timingText:'', evidence:[] };
    }
    var ctx = __zwCompositeScore(zw, type||'general');
    var score = ctx.score;
    var dir = __zwDirFromScore(score);
    var focus = ctx.focus;
    var cfg = ctx.cfg;
    var focusPalaceName = (focus.palace && focus.palace.name) || cfg.palace;
    var majorNames = focus.majors.map(function(s){ return s.name; }).join('、') || '無主星主導';
    var goodNames = focus.goods.slice(0,3).map(function(s){ return s.name || s.hua; }).join('、');
    var riskNames = focus.risks.slice(0,3).map(function(s){ return s.name || s.hua; }).join('、');
    var why1 = '主題落在「'+focusPalaceName+'」，主星組合為 '+majorNames+'，這是紫微判這題的第一層。';
    var why2 = goodNames ? '此宮目前可用的助力是 '+goodNames+'。' : '此宮沒有明顯吉曜加持，所以不能只看表面期待。';
    var why3 = riskNames ? '真正的阻力在 '+riskNames+'，這會讓事情不是不能成，而是會先卡。' : '煞忌壓力不算重，代表這題主要靠你怎麼抓節奏。';
    var riskPoint = riskNames ? '最需要提防的是「'+riskNames+'」帶來的拖延、誤判或硬碰硬。' : '目前最大風險不是外部，而是你自己判斷過快。';
    if(ctx.dx && ctx.dx.level) riskPoint += ' 另外，你目前走「'+ctx.dx.palaceName+'」大限（'+ctx.dx.level+'），十年背景也會放大這題的體感。';
    var actions = __zwActionByType(type||'general', dir, focus);
    var strategies = [
      '判斷順序：先看'+focusPalaceName+'，再看三方四正，最後才看你當下情緒。',
      ctx.dx ? '大限主軸在'+ctx.dx.palaceName+'，所以這題不能脫離你這十年的主線。':'先天結構比短期情緒更重要。',
      ctx.ln ? (new Date().getFullYear())+'年流年有在推動這題，但成不成要看你有沒有避開忌點。':'目前更偏結構題，不是單看今年一時起伏。'
    ];
    return {
      yesNoAnswer: __zwAnswerFromScore(score, cfg),
      direction: dir,
      score: score,
      confidence: __zwConfidence(zw, focus, ctx.dx, ctx.ln),
      why1: why1,
      why2: why2,
      why3: why3,
      riskPoint: riskPoint,
      action1: actions[0] || '',
      action2: actions[1] || '',
      strategies: strategies,
      timingText: __zwTimingText(zw, type||'general', focus, ctx.dx, ctx.ln),
      evidence: [why1, why2, why3],
      palace: focusPalaceName,
      palaceScore: focus.score,
      mainStars: focus.majors.map(function(s){ return s.name; }),
      goodStars: focus.goods.map(function(s){ return s.name || s.hua; }),
      riskStars: focus.risks.map(function(s){ return s.name || s.hua; }),
      question: userQuestion || ''
    };
  };

  window.buildZiweiNarrative = function(qr, zw, type){
    if(!qr || !zw) return null;
    var label = (__zwCfg(type||'general').label || '整體');
    var dx = __zwFindCurrentDx(zw);
    var ln = __zwFindCurrentLn(zw);
    var situation = '這題先看「'+qr.palace+'」。紫微給出的分數是 '+qr.score+'/100，代表'+(qr.direction==='positive'?'局面是能推的，只是要抓順勢點。':qr.direction==='negative'?'局面偏逆風，先天或時機都有壓力。':'局面不是完全沒機會，但不屬於直接衝就會成的格局。');
    var coreConflict = qr.riskStars && qr.riskStars.length
      ? '核心矛盾不在你想不想做，而在「'+qr.riskStars.slice(0,2).join('、')+'」代表的壓力。這通常是現實條件、關係互動或情緒執念卡住。'
      : '核心矛盾不大，真正考驗是你能不能穩住節奏，不要自己把局勢玩壞。';
    var trend = dx
      ? '十年背景走在「'+dx.palaceName+'」大限，表示這題不是短暫事件，而是你這階段人生主題的一部分。'+(ln&&ln.mingPalace ? ('今年流年又走到「'+ln.mingPalace+'」，所以感受會更明顯。') : '')
      : '目前看起來這題更像先天結構題，短期起伏不如長期定位重要。';
    var risk = qr.riskPoint || ('這題真正風險在於你只看單一表象，沒看見紫微盤背後的結構。');
    var advice = [qr.action1, qr.action2].filter(Boolean).join(' ');
    var timing = qr.timingText || '';
    return { situation:situation, coreConflict:coreConflict, trend:trend, risk:risk, advice:advice, timing:timing };
  };

  window.renderZiweiFunZone = function(){
    var box1 = document.getElementById('zw-daily-signal-content');
    var box2 = document.getElementById('zw-decision-card-content');
    var box3 = document.getElementById('zw-timing-card-content');
    if(!box1 && !box2 && !box3) return;
    if(!S || !S.ziwei){
      [box1,box2,box3].forEach(function(el){ if(el) el.innerHTML = '<p class="text-dim">需要先完成基本資料才能顯示紫微趣味區。</p>'; });
      return;
    }
    var type = S.form ? (S.form.type || 'general') : 'general';
    var qr = null, na = null;
    try { qr = analyzeZiweiQuestion(S.ziwei, type, (S.form&&S.form.question)||''); } catch(e) {}
    try { na = buildZiweiNarrative(qr, S.ziwei, type); } catch(e) {}
    var year = new Date().getFullYear();
    var dx = __zwFindCurrentDx(S.ziwei);
    var ln = __zwFindCurrentLn(S.ziwei);
    if(box1){
      var h1 = '<div style="padding:.6rem;background:rgba(212,175,55,.06);border-radius:8px">';
      h1 += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.35rem;font-size:.92rem">🪐 今日紫微主調卡</p>';
      h1 += '<p style="font-size:.86rem;margin:.25rem 0"><strong>主題宮位：</strong>'+ (qr ? qr.palace : '命宮') +'</p>';
      h1 += '<p style="font-size:.86rem;margin:.25rem 0"><strong>當前調性：</strong>'+ (qr ? qr.yesNoAnswer : '資料不足') +'</p>';
      if(dx) h1 += '<p style="font-size:.78rem;opacity:.7;margin-top:.35rem">大限：'+dx.palaceName+'（'+dx.ageStart+'-'+dx.ageEnd+'歲・'+(dx.level||'')+'）</p>';
      h1 += '</div>';
      box1.innerHTML = h1;
    }
    if(box2){
      var h2 = '<div style="padding:.6rem;background:rgba(148,163,184,.06);border-radius:8px">';
      h2 += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.35rem;font-size:.92rem">🧭 紫微決策提醒卡</p>';
      h2 += '<p style="font-size:.85rem;margin:.25rem 0;color:var(--c-gold)"><strong>該做：</strong>' + (qr && qr.action1 ? qr.action1 : '先看主題宮位再決定。') + '</p>';
      h2 += '<p style="font-size:.85rem;margin:.25rem 0;color:#fca5a5"><strong>別做：</strong>' + (qr && qr.riskPoint ? qr.riskPoint : '不要情緒化判斷。') + '</p>';
      if(na && na.coreConflict) h2 += '<p style="font-size:.8rem;margin-top:.35rem;opacity:.8">'+na.coreConflict+'</p>';
      h2 += '</div>';
      box2.innerHTML = h2;
    }
    if(box3){
      var h3 = '<div style="padding:.6rem;background:rgba(74,222,128,.04);border-radius:8px">';
      h3 += '<p style="font-weight:600;color:var(--c-gold);margin-bottom:.35rem;font-size:.92rem">⏳ 紫微應期節奏卡</p>';
      h3 += '<p style="font-size:.85rem;margin:.25rem 0"><strong>'+year+'年節奏：</strong>' + (qr && qr.timingText ? qr.timingText : '先看流年再看行動。') + '</p>';
      if(ln && ln.mingPalace) h3 += '<p style="font-size:.85rem;margin:.25rem 0"><strong>流年命宮：</strong>'+ln.mingPalace+'</p>';
      if(qr && qr.strategies && qr.strategies.length) h3 += '<p style="font-size:.8rem;margin-top:.35rem;color:var(--c-gold)">▸ '+qr.strategies[0]+'</p>';
      h3 += '</div>';
      box3.innerHTML = h3;
    }
  };

  // 覆寫維度引擎：紫微不再只吐 tag，而是直接用正式問事核心
  analyzeZiweiDimension = function(ziwei, type) {
    try {
      if (!ziwei) return safeMidResult('紫微', '紫微資料不存在');
      var qr = (typeof analyzeZiweiQuestion === 'function') ? analyzeZiweiQuestion(ziwei, type, (typeof S!=='undefined'&&S.form?S.form.question:'') || '') : null;
      var tags = (typeof analyzeZiweiTags === 'function') ? analyzeZiweiTags(ziwei, type) : [];
      if(!qr){
        var score0 = (typeof ziweiScoreFromTags === 'function') ? ziweiScoreFromTags(tags) : 50;
        return { dim:'紫微', score:score0, dir:score0>=60?'pos':score0<=40?'neg':'mid', confidence:50, timing:'long', verdict:'紫微中性', reason:'紫微資料不足', detail:'', tags:tags };
      }
      var dirMap = { positive:'pos', negative:'neg', neutral:'mid' };
      return {
        dim:'紫微',
        score:qr.score,
        dir:dirMap[qr.direction] || 'mid',
        confidence:qr.confidence || 50,
        timing:'long',
        verdict:qr.yesNoAnswer,
        reason:__zwFormatReasons([qr.why1, qr.why2, qr.why3]),
        detail:(qr.riskPoint||'') + (qr.timingText ? '｜'+qr.timingText : ''),
        tags:tags
      };
    } catch(e) { return safeMidResult('紫微', '紫微分析異常：'+e.message); }
  };

  // 覆寫故事輸出：讓所有舊入口改吃新敘事
  generateZiweiStory = function(type, zw){
    try {
      if(!zw) return '';
      var qr = analyzeZiweiQuestion(zw, type||'general', (typeof S!=='undefined'&&S.form?S.form.question:'') || '');
      var na = buildZiweiNarrative(qr, zw, type||'general');
      if(!qr || !na) return '';
      var html = '';
      html += '<div class="insight-card"><div class="insight-title">🪐 紫微直判：'+qr.yesNoAnswer+'</div>';
      html += '<div class="insight-sub">分數：'+qr.score+'/100 ｜ 信心度：'+qr.confidence+'% ｜ 主題宮位：'+qr.palace+'</div></div>';
      html += '<div style="margin-top:.7rem">';
      html += '<p style="font-size:.88rem;line-height:1.75"><strong>目前局面：</strong>'+na.situation+'</p>';
      html += '<p style="font-size:.88rem;line-height:1.75"><strong>核心矛盾：</strong>'+na.coreConflict+'</p>';
      html += '<p style="font-size:.88rem;line-height:1.75"><strong>發展走向：</strong>'+na.trend+'</p>';
      html += '<p style="font-size:.88rem;line-height:1.75;color:#fca5a5"><strong>風險提醒：</strong>'+na.risk+'</p>';
      html += '<p style="font-size:.88rem;line-height:1.75;color:var(--c-gold)"><strong>行動建議：</strong>'+na.advice+'</p>';
      if(na.timing) html += '<p style="font-size:.84rem;line-height:1.65"><strong>應期提示：</strong>'+na.timing+'</p>';
      html += '</div>';
      return html;
    } catch(e) { return ''; }
  };
})();


/* =============================================================
   [UPGRADE v7] 梅花 / 塔羅正式問事核心 + 七維接線統一
   ============================================================= */

function _toPosNegMidFromScore(score){
  return score>=60?'pos':score<=40?'neg':'mid';
}
function _toYNByDir(dir, score){
  if(dir==='pos') return score>=70?'可以，且有明顯機會':'可以，但要抓節奏';
  if(dir==='neg') return score<=30?'不建議，阻力偏大':'暫時不宜硬推';
  return '有機會，但仍有變數';
}
function _timingTextFromBias(tb){
  return tb==='short'?'短期1-4週內最有感':tb==='mid'?'中期1-3個月逐步明朗':tb==='long'?'長期累積後較有結果':'時間窗混合，先觀察再判斷';
}
function _extractTopTagReasons(tags, maxN){
  return (tags||[]).slice().sort(function(a,b){return (b.weight||0)-(a.weight||0);}).slice(0,maxN||3).map(function(t){return t.label||t.tag||'';}).filter(Boolean);
}

function analyzeMeihuaQuestion(mh, type, question){
  try{
    if(!mh) return { score:50, direction:'neutral', confidence:20, yesNoAnswer:'資料不足', finalAnswer:'梅花資料不足，無法判讀。', tags:[] };
    var t=type||'general';
    var analysis = null;
    if(typeof buildMeihuaOutput==='function') analysis = buildMeihuaOutput(mh, t);
    if(!analysis && typeof analyzeMeihua==='function') analysis = analyzeMeihua(mh, t);
    analysis = analysis || mh.analysis || {};
    var tags = (typeof analyzeMeihuaTags==='function') ? analyzeMeihuaTags(mh, t) : [];
    var score = (typeof meihuaScoreFromTags==='function') ? meihuaScoreFromTags(tags) : (analysis.summary&&/吉|順|利/.test(analysis.summary)?64:analysis.summary&&/凶|阻|壓/.test(analysis.summary)?36:50);
    var dir = _toPosNegMidFromScore(score);
    var nb = analysis.narrativeBlocks || {};
    var rel = (mh.ty&&mh.ty.r)||'';
    var f = (mh.ty&&mh.ty.f)||'';
    var timingBias = 'short';
    if(tags && tags.length && typeof mergeTiming==='function') timingBias = mergeTiming(tags) || 'short';
    var why = [];
    if(nb.situation) why.push(nb.situation);
    if(nb.coreTension) why.push(nb.coreTension);
    if(nb.trend) why.push(nb.trend);
    if(why.length<3) why = why.concat(_extractTopTagReasons(tags, 3-why.length));
    var riskPoint = '';
    if(analysis.risk) {
      if(typeof analysis.risk === 'string') riskPoint = analysis.risk;
      else if(analysis.risk.points && analysis.risk.points[0]) riskPoint = analysis.risk.points[0];
      else if(analysis.risk.level) riskPoint = {low:'風險偏低',mid:'有一定變數',high:'風險明顯'}[analysis.risk.level]||'';
    }
    if(!riskPoint && analysis.mainRisk) riskPoint = typeof analysis.mainRisk === 'string' ? analysis.mainRisk : '';
    if(!riskPoint && nb.risk) riskPoint = typeof nb.risk === 'string' ? nb.risk : '';
    if(!riskPoint && rel==='用克體') riskPoint = '外在壓力偏強，硬推容易失手';
    else if(!riskPoint && rel==='體生用') riskPoint = '你會先付出很多，回收較慢';
    var action = [];
    if(analysis.strategy) {
      if(typeof analysis.strategy === 'string') action.push(analysis.strategy);
      else if(Array.isArray(analysis.strategy)) action = action.concat(analysis.strategy);
      else if(analysis.strategy.advice && Array.isArray(analysis.strategy.advice)) action = action.concat(analysis.strategy.advice);
      else if(analysis.strategy.mode) action.push({push:'積極推進',wait:'耐心等待',stabilize:'穩守現局',retreat:'先行退守',observe:'觀察為主'}[analysis.strategy.mode]||'');
    }
    if(analysis.actionAdvice && Array.isArray(analysis.actionAdvice)) action = action.concat(analysis.actionAdvice);
    if(action.length<2){
      if(rel==='用生體') action.push('可主動推進，但先抓住外援與時機');
      else if(rel==='比和') action.push('穩定推進即可，重點在持續與一致');
      else if(rel==='體克用') action.push('可以掌控，但要準備多花力氣');
      else if(rel==='體生用') action.push('先控管投入，避免自己耗損過度');
      else if(rel==='用克體') action.push('先觀望與修正條件，不要硬碰硬');
    }
    action = action.filter(Boolean).slice(0,3);
    var yesNoAnswer = _toYNByDir(dir, score);
    if(rel==='用生體' && score>=58) yesNoAnswer='可以，外力明顯站在你這邊';
    else if(rel==='比和' && score>=55) yesNoAnswer='可以，局勢相對穩定';
    else if(rel==='體克用') yesNoAnswer='能做成，但要靠你自己扛';
    else if(rel==='體生用') yesNoAnswer='不是不能做，但你會先累';
    else if(rel==='用克體') yesNoAnswer='暫時不宜硬推，先避其鋒';
    var finalAnswer = (nb.situation?nb.situation+'。':'') + (nb.trend?nb.trend+'。':'') + (action[0]?'建議：'+action[0]+'。':'') + (_timingTextFromBias(timingBias)?'時機：'+_timingTextFromBias(timingBias)+'。':'');
    return {
      score: score,
      direction: dir==='pos'?'positive':dir==='neg'?'negative':'neutral',
      confidence: (typeof calcConfidenceFromTags==='function') ? calcConfidenceFromTags(tags) : 68,
      yesNoAnswer: yesNoAnswer,
      why1: why[0]||'', why2: why[1]||'', why3: why[2]||'',
      riskPoint: riskPoint||'',
      action1: action[0]||'', action2: action[1]||'', action3: action[2]||'',
      timingBias: timingBias,
      timingText: (analysis.timing&&analysis.timing.windowLabel?analysis.timing.windowLabel+'｜':'') + (nb.timing||_timingTextFromBias(timingBias)),
      verdictShort: dir==='pos'?'梅花偏吉':dir==='neg'?'梅花有阻':'梅花混合',
      finalAnswer: finalAnswer,
      tags: tags,
      analysis: analysis
    };
  }catch(e){
    return { score:50, direction:'neutral', confidence:20, yesNoAnswer:'分析異常', finalAnswer:'梅花問事引擎異常：'+e.message, tags:[] };
  }
}

function analyzeTarotQuestion(tarot, type, question){
  try{
    var drawn = tarot && tarot.drawn ? tarot.drawn : tarot;
    if(!drawn || drawn.length<10) return { score:50, direction:'neutral', confidence:20, yesNoAnswer:'資料不足', finalAnswer:'塔羅牌陣不足，無法判讀。', tags:[] };
    var t=type||'general';
    var tags = (typeof analyzeTarotTags==='function') ? analyzeTarotTags(drawn, t) : [];
    var spread = (typeof analyzeTarotSpread==='function') ? analyzeTarotSpread(drawn, t) : null;
    var sum = (typeof buildTarotAnalysisSummary==='function') ? buildTarotAnalysisSummary(drawn, t) : null;
    var story = (typeof generateTarotStory==='function') ? generateTarotStory(t, drawn) : '';
    var score = spread && spread.score ? spread.score : ((typeof tarotScoreFromTags==='function') ? tarotScoreFromTags(tags) : 50);
    var dir = _toPosNegMidFromScore(score);
    if(sum && sum.direction){
      if(sum.direction==='positive' || sum.direction==='reversible_positive') dir='pos';
      else if(sum.direction==='negative' || sum.direction==='reversible_negative') dir='neg';
    }
    var yesNoAnswer = _toYNByDir(dir, score);
    if(sum){
      if(sum.direction==='reversible_positive') yesNoAnswer='前面有卡點，但後面有翻盤機會';
      if(sum.direction==='reversible_negative') yesNoAnswer='起初看似可行，但後段容易走偏';
    }
    var insightList = [];
    if(spread && spread.insights) insightList = spread.insights.slice(0,4).map(function(it){ return (it.pos?it.pos+'：':'') + (it.meaning||it.card||''); });
    if(insightList.length<3) insightList = insightList.concat(_extractTopTagReasons(tags, 3-insightList.length));
    var riskPoint = '';
    if(sum && sum.conflictFlags && sum.conflictFlags.length) riskPoint = sum.conflictFlags[0];
    if(!riskPoint && spread && spread.gdAnalysis && spread.gdAnalysis.priorityCards && spread.gdAnalysis.priorityCards.obstacle) riskPoint = spread.gdAnalysis.priorityCards.obstacle;
    var action = [];
    if(sum && sum.supportFlags && sum.supportFlags.length) action.push('優先順著牌陣支持點行動：'+sum.supportFlags[0]);
    if(sum && sum.selfExternalSync==='一致') action.push('你自己與外在環境方向一致，可以主動推進');
    else if(sum && sum.selfExternalSync) action.push('先處理自己與外在不同步的問題，再推進');
    if(sum && sum.timing) action.push('節奏上偏向：'+sum.timing);
    if(action.length<2){
      action.push(dir==='pos'?'可以行動，但先處理阻礙位牌義':'先處理阻礙位與根因位，再決定下一步');
      action.push('十字陣重點看2、3、8、10位，別只看結果牌好不好');
    }
    var finalAnswer = (story? String(story).replace(/<br\s*\/?>/g,' ').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim() : '');
    if(finalAnswer.length>220) finalAnswer = finalAnswer.slice(0,220)+'…';
    if(!finalAnswer) finalAnswer = yesNoAnswer+'。'+(insightList[0]||'')+'。'+(action[0]||'');
    return {
      score: score,
      direction: dir==='pos'?'positive':dir==='neg'?'negative':'neutral',
      confidence: (typeof calcConfidenceFromTags==='function') ? calcConfidenceFromTags(tags) : 72,
      yesNoAnswer: yesNoAnswer,
      why1: insightList[0]||'', why2: insightList[1]||'', why3: insightList[2]||'',
      riskPoint: riskPoint||'',
      action1: action[0]||'', action2: action[1]||'', action3: action[2]||'',
      timingBias: 'short',
      timingText: sum && sum.timing ? ('短期牌陣訊號：'+sum.timing) : '塔羅屬短中期事件判讀，近期1-4週最敏感',
      verdictShort: dir==='pos'?'塔羅偏正面':dir==='neg'?'塔羅有壓力':'塔羅混合',
      finalAnswer: finalAnswer,
      tags: tags,
      spread: spread,
      summary: sum
    };
  }catch(e){
    return { score:50, direction:'neutral', confidence:20, yesNoAnswer:'分析異常', finalAnswer:'塔羅問事引擎異常：'+e.message, tags:[] };
  }
}

// 覆蓋維度分析：改用正式問事核心
analyzeMeihuaDimension = function(mh, type){
  try{
    var qr = analyzeMeihuaQuestion(mh, type||'general', '');
    var tags = qr.tags || ((typeof analyzeMeihuaTags==='function'&&mh)?analyzeMeihuaTags(mh, type||'general'):[]);
    return normalizeDimResult('梅花', {
      score: qr.score||50,
      dir: qr.direction==='positive'?'pos':qr.direction==='negative'?'neg':'mid',
      confidence: qr.confidence||50,
      timing: qr.timingBias||'short',
      tags: tags,
      verdict: qr.verdictShort || '梅花問事結果',
      reason: [qr.why1, qr.why2, qr.why3].filter(Boolean).join('；') || '梅花卦象已計算',
      detail: qr.finalAnswer || ''
    });
  }catch(e){ return safeMidResult('梅花','梅花分析異常：'+e.message); }
};

analyzeTarotDimension = function(tarot, type){
  try{
    var qr = analyzeTarotQuestion(tarot, type||'general', '');
    var tags = qr.tags || [];
    return normalizeDimResult('塔羅', {
      score: qr.score||50,
      dir: qr.direction==='positive'?'pos':qr.direction==='negative'?'neg':'mid',
      confidence: qr.confidence||50,
      timing: qr.timingBias||'short',
      tags: tags,
      verdict: qr.verdictShort || '塔羅問事結果',
      reason: [qr.why1, qr.why2, qr.why3].filter(Boolean).join('；') || '塔羅牌陣已計算',
      detail: qr.finalAnswer || ''
    });
  }catch(e){ return safeMidResult('塔羅','塔羅分析異常：'+e.message); }
};

// 統一七維入口：全部走各自正式 Dimension Analyzer
buildUnifiedDimensionResults = function(type){
  var t = type || 'general';
  var results = [];
  try{ if(typeof S!=='undefined' && S.bazi) results.push(analyzeBaziDimension(S.bazi, t)); }catch(e){}
  try{ if(typeof S!=='undefined' && S.ziwei) results.push(analyzeZiweiDimension(S.ziwei, t)); }catch(e){}
  try{ if(typeof S!=='undefined' && S.meihua) results.push(analyzeMeihuaDimension(S.meihua, t)); }catch(e){}
  try{ if(typeof S!=='undefined' && S.tarot && S.tarot.drawn && S.tarot.drawn.length>=10) results.push(analyzeTarotDimension(S.tarot, t)); }catch(e){}
  try{ if(typeof S!=='undefined' && S.natal) results.push(analyzeNatalDimension(S.natal, t)); }catch(e){}
  try{ if(typeof S!=='undefined' && S.jyotish) results.push(analyzeJyotishDimension(S.jyotish, t)); }catch(e){}
  try{
    var _nr=(typeof nameResult!=='undefined')?nameResult:null;
    var _zr=(typeof zodiacNameResult!=='undefined')?zodiacNameResult:null;
    if(_nr||_zr) results.push(analyzeNameDimension(_nr,_zr,t));
  }catch(e){}
  return results;
};

// 覆蓋渲染：梅花上方加入正式問事摘要
