// ═══════════════════════════════════════════════════════════════════════
// [PATCH v9] API解析強化 + 八字用神為底的七維能量推薦
// 目標：
// 1) API payload 帶入真正的七維交叉訊號與口吻規範
// 2) 能量推薦嚴格先過八字喜忌，再由七維修正當下需求
// 3) AI結果可渲染字串或結構化物件
// ═══════════════════════════════════════════════════════════════════════
(function(){
  function _aiTxt(v){ return v==null ? '' : String(v).replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim(); }
  function _aiUniq(arr, limit){
    var seen={}, out=[];
    (arr||[]).forEach(function(x){
      var t = _aiTxt(typeof x==='string'?x:(x&&x.text)||'').slice(0,80);
      if(!t || seen[t]) return;
      seen[t]=1; out.push(typeof x==='string'?{text:t}:Object.assign({},x,{text:t}));
    });
    return typeof limit==='number' ? out.slice(0,limit) : out;
  }
  function _aiQuestionType(type){
    var t=(type||'general').toLowerCase();
    if(t==='love') return 'love';
    if(t==='career'||t==='work'||t==='job') return 'career';
    if(t==='wealth'||t==='money'||t==='finance') return 'wealth';
    if(t==='health') return 'health';
    if(t==='relationship'||t==='social') return 'relationship';
    if(t==='family'||t==='home') return 'family';
    return 'general';
  }
  function _aiNeedLabel(k){
    return ({stable:'穩定安定',protect:'防護淨化',action:'行動突破',love:'關係修復/桃花',wealth:'聚焦財氣',clarity:'理清思緒',heal:'療癒修復'})[k] || '穩定支持';
  }
  function _aiNeedKeywords(k){
    return {
      stable:['穩','定','安神','安定','平衡','接地','安全感','穩住'],
      protect:['護身','防護','辟邪','擋煞','淨化','負能量','轉化','守護'],
      action:['行動','決斷','果斷','衝勁','執行','突破','自信','領導'],
      love:['桃花','愛情','人緣','魅力','心輪','修復','關係','溫柔'],
      wealth:['財運','聚財','正財','偏財','事業','資源','招財','守財'],
      clarity:['智慧','專注','思緒','表達','直覺','洞察','學習','判斷'],
      heal:['療癒','休息','睡眠','修復','舒緩','身心','柔和','平靜']
    }[k] || [];
  }
  function _aiScoreNeedText(text, need){
    var s=0, kws=_aiNeedKeywords(need), t=_aiTxt(text);
    kws.forEach(function(k){ if(t.indexOf(k)>=0) s+=1; });
    return s;
  }
  function _aiDeriveNeeds(type, synth){
    var t=_aiQuestionType(type);
    var texts=[];
    (synth&&synth.supports||[]).forEach(function(x){texts.push(_aiTxt(x));});
    (synth&&synth.risks||[]).forEach(function(x){texts.push(_aiTxt(x));});
    if(synth&&synth.directAnswer) texts.push(_aiTxt(synth.directAnswer));
    if(synth&&synth.strategySummary) texts.push(_aiTxt(synth.strategySummary));
    var score={stable:0,protect:0,action:0,love:0,wealth:0,clarity:0,heal:0};
    texts.forEach(function(t0){
      Object.keys(score).forEach(function(k){ score[k]+=_aiScoreNeedText(t0,k); });
      if(/焦慮|不安|反覆|消耗|內耗|心急|慌|沒安全感/.test(t0)) score.stable+=2, score.heal+=1;
      if(/小人|是非|負能量|壓力|煞|衝突|外耗|被影響/.test(t0)) score.protect+=2;
      if(/拖延|卡住|不敢動|猶豫|沒魄力|推不動/.test(t0)) score.action+=2;
      if(/桃花|復合|曖昧|感情|互動|關係|冷掉/.test(t0)) score.love+=2;
      if(/財|收入|資源|守不住|漏財|投資|事業/.test(t0)) score.wealth+=2;
      if(/想不清楚|混亂|溝通|判斷|方向/.test(t0)) score.clarity+=2;
      if(/累|失眠|療癒|修復|情傷|恢復/.test(t0)) score.heal+=2;
    });
    if(t==='love') score.love+=3, score.heal+=1;
    if(t==='career') score.action+=2, score.clarity+=1, score.wealth+=1;
    if(t==='wealth') score.wealth+=3, score.action+=1, score.stable+=1;
    if(t==='health') score.heal+=3, score.stable+=2, score.protect+=1;
    if(t==='relationship') score.love+=1, score.clarity+=2, score.protect+=1;
    if(t==='family') score.stable+=2, score.heal+=1, score.protect+=1;
    var top=Object.keys(score).sort(function(a,b){return score[b]-score[a];});
    return { primary: top[0]||'stable', secondary: top[1]||'clarity', scoreMap:score };
  }
  function _aiEnergyExplain(primary, secondary, synth){
    var dir = synth&&synth.finalDir;
    var tone = dir==='neg'
      ? '你現在比較需要先把狀態穩住，再談放大結果。'
      : dir==='pos'
      ? '你不是沒有機會，重點是把對的能量放在最需要的位置。'
      : '這題不是完全沒有機會，而是先穩住節奏，效果會比硬推更好。';
    return tone + ' 這次先以「' + _aiNeedLabel(primary) + '」為主，再用「' + _aiNeedLabel(secondary) + '」做輔助。';
  }
  function _aiPickProducts(allowedEls, preferredEls, needs){
    if(typeof REAL_PRODUCTS==='undefined') return [];
    var all=[];
    Object.keys(REAL_PRODUCTS).forEach(function(k){ if(Array.isArray(REAL_PRODUCTS[k])) all=all.concat(REAL_PRODUCTS[k]); });
    var allowSet = new Set((allowedEls||[]).filter(Boolean));
    var prefMap = {};
    (preferredEls||[]).forEach(function(el,idx){ prefMap[el]=idx===0?3:idx===1?2:1; });
    var seen={};
    var scored=[];
    all.forEach(function(p){
      if(!p || !p.n || seen[p.n]) return;
      seen[p.n]=1;
      if(allowSet.size && p.el && !allowSet.has(p.el) && p.el!=='全') return;
      var s=0, name=_aiTxt(p.n), desc=_aiTxt(p.d);
      if(prefMap[p.el]) s += prefMap[p.el]*5;
      if(p.el==='全') s += 3;
      (needs||[]).forEach(function(need, idx){
        var kws=_aiNeedKeywords(need);
        kws.forEach(function(k){ if(name.indexOf(k)>=0) s += idx===0?4:2; if(desc.indexOf(k)>=0) s += idx===0?3:1; });
        if(need==='protect' && /黑曜|天鐵|舍利|關公|龍牌|黑碧璽|黑髮|彼得/.test(name)) s += idx===0?7:4;
        if(need==='stable' && /茶晶|白水晶|檀|舍利|鐵膽|月光/.test(name)) s += idx===0?6:3;
        if(need==='action' && /鈦晶|天鐵|金髮|太陽|虎眼|彼得/.test(name)) s += idx===0?7:4;
        if(need==='love' && /粉晶|草莓|摩根|薔薇|碧璽|月光/.test(name)) s += idx===0?7:4;
        if(need==='wealth' && /綠幽靈|鈦晶|黃水晶|金髮|龍宮舍利|利比亞|抹茶幽靈/.test(name)) s += idx===0?7:4;
        if(need==='clarity' && /海藍寶|堇青石|青晶石|藍磷灰|白水晶|紫水晶/.test(name)) s += idx===0?6:3;
        if(need==='heal' && /紫水晶|月光|摩根|薔薇|海藍寶|白龍宮舍利/.test(name)) s += idx===0?6:3;
      });
      if(/天鐵|隕石/.test(name)) s += 1;
      if(/龍宮舍利/.test(name)) s += 1;
      if(s>0) scored.push(Object.assign({__score:s}, p));
    });
    return scored.sort(function(a,b){ return b.__score-a.__score; }).slice(0,4);
  }
  function buildSevenEnergyRecommendation(type, question){
    try{
      var b = (typeof S!=='undefined') ? S.bazi : null;
      var t = _aiQuestionType(type || (S.form&&S.form.type) || 'general');
      var q = question || (S.form&&S.form.question) || '';
      var synth = (typeof getSevenDimAnalysis==='function') ? getSevenDimAnalysis(t, q) : null;
      var fav = b && Array.isArray(b.fav) ? b.fav.filter(Boolean).slice(0,2) : [];
      var unfav = b && Array.isArray(b.unfav) ? b.unfav.filter(Boolean).slice(0,3) : [];
      var needs = _aiDeriveNeeds(t, synth||{});
      var picks = _aiPickProducts(fav, fav, [needs.primary, needs.secondary]);
      var reasons=[];
      if(fav[0]) reasons.push('能量建議仍以八字第一用神「'+fav[0]+'」為主。');
      if(fav[1]) reasons.push('第二用神「'+fav[1]+'」可作輔助，讓配戴不只補本命，也更貼近這次問題。');
      reasons.push('七維交叉後，這次優先需求落在「'+_aiNeedLabel(needs.primary)+'」；次要需求是「'+_aiNeedLabel(needs.secondary)+'」。');
      if(unfav.length) reasons.push('需避開的忌神方向：'+unfav.join('、')+'。');
      var warm = _aiEnergyExplain(needs.primary, needs.secondary, synth||{});
      return {
        questionType:t,
        primaryNeed:needs.primary,
        secondaryNeed:needs.secondary,
        primaryNeedLabel:_aiNeedLabel(needs.primary),
        secondaryNeedLabel:_aiNeedLabel(needs.secondary),
        firstYongshen:fav[0]||'',
        secondYongshen:fav[1]||'',
        avoid:unfav,
        rationale:reasons,
        warmText:warm,
        picks:picks.map(function(p){ return {name:p.n, element:p.el, desc:p.d||'', price:p.price||'', shopee:p.shopee||'https://tw.shp.ee/2n5Mo2w', cat:p.cat||'手鍊'}; })
      };
    }catch(e){
      return { primaryNeed:'stable', secondaryNeed:'clarity', rationale:['能量推薦暫時無法完整建立：'+e.message], picks:[] };
    }
  }
  window.buildSevenEnergyRecommendation = buildSevenEnergyRecommendation;

  // ═══════════════════════════════════════════════════════════════
  // _buildPayload v2 — 送「具體命理判讀」而非「抽象標籤」
  // 核心改動：梅花送 narrativeBlocks、八字送大運細節、塔羅送7張、紫微送四化
  // ═══════════════════════════════════════════════════════════════
  var _buildPayloadBase = _buildPayload;

  _buildPayload = function(){
    var p = _buildPayloadBase();

    try {
      var q = (typeof S !== 'undefined' && S.form) ? (S.form.question || '') : '';
      var ft = (typeof S !== 'undefined' && S.form) ? (S.form.type || 'general') : 'general';

      // ═══ 1. 七維綜合分析 ═══
      var synth = (typeof getSevenDimAnalysis === 'function') ? getSevenDimAnalysis(ft, q) : null;

      if (synth) {
        p.seven = {
          finalScore: synth.finalScore,
          finalDir: synth.finalDir,
          finalConfidence: synth.finalConfidence,
          consensus: synth.consensus,
          timingBias: synth.timingBias,
          conflictState: synth.conflictState || 'none',
          directAnswer: synth.directAnswer || '',
          whySummary: synth.whySummary || '',
          bottleneckSummary: synth.bottleneckSummary || '',
          strategySummary: synth.strategySummary || '',
          timingSummary: synth.timingSummary || '',
          supports: _aiUniq(synth.supports || [], 5).map(function(x) { return x.text || x; }),
          risks: _aiUniq(synth.risks || [], 5).map(function(x) { return x.text || x; })
        };
      }

      // ═══ 2. 各維度具體判讀（帶 verdict + reason + detail + 具體 tags）═══
      if (synth && synth.dimResults && synth.dimResults.length) {
        p.dimReadings = synth.dimResults.map(function(d) {
          var keyTags = (d.tags || [])
            .filter(function(t) { return t.weight >= 2; })
            .sort(function(a, b) { return (b.weight || 1) - (a.weight || 1); })
            .slice(0, 8)
            .map(function(t) {
              var s = (t.direction === 'pos' ? '+' : t.direction === 'neg' ? '-' : '~') + ' ' + (t.label || t.tag || '');
              if (t.detail) s += '（' + t.detail.substring(0, 80) + '）';
              return s;
            });
          return {
            dim: d.dim,
            score: d.score,
            dir: d.dir,
            verdict: d.verdict || '',
            reason: d.reason || '',
            detail: (d.detail || '').substring(0, 200),
            tags: keyTags
          };
        });
      }

      // ═══ 3. 梅花具體敘事（核心改動：送 narrativeBlocks 而非只送 ben/bian/rel）═══
      if (typeof S !== 'undefined' && S.meihua) {
        var mh = S.meihua;
        try {
          var mhAnalysis = (typeof analyzeMeihua === 'function') ? analyzeMeihua(mh, ft) : null;
          if (mhAnalysis && mhAnalysis.narrativeBlocks) {
            p.meihuaNarrative = {};
            var nb = mhAnalysis.narrativeBlocks;
            if (nb.situation) p.meihuaNarrative.situation = nb.situation;
            if (nb.coreTension) p.meihuaNarrative.coreTension = nb.coreTension;
            if (nb.trend) p.meihuaNarrative.trend = nb.trend;
            if (nb.risk) p.meihuaNarrative.risk = nb.risk;
            if (nb.timing) p.meihuaNarrative.timing = nb.timing;
            if (nb.action) p.meihuaNarrative.action = nb.action;
          }
          if (mhAnalysis && mhAnalysis.signals && mhAnalysis.signals.length) {
            p.dims.meihua = p.dims.meihua || {};
            p.dims.meihua.signals = mhAnalysis.signals.slice(0, 5);
          }
          if (mhAnalysis) {
            p.dims.meihua = p.dims.meihua || {};
            if (mhAnalysis.huGua) p.dims.meihua.huGua = mhAnalysis.huGua.effect || '';
            if (mhAnalysis.bianGua) p.dims.meihua.bianGua = mhAnalysis.bianGua.effect || '';
            if (mhAnalysis.timing) {
              p.dims.meihua.timing = mhAnalysis.timing.label + '（' + (mhAnalysis.timing.range || '') + '）';
              if (mhAnalysis.timing.note) p.dims.meihua.timingNote = mhAnalysis.timing.note;
            }
            if (mhAnalysis.risk) p.dims.meihua.risk = mhAnalysis.risk;
            if (mhAnalysis.strategy) p.dims.meihua.actionAdvice = mhAnalysis.strategy.slice(0, 3);
            if (mhAnalysis.structure) {
              if (mhAnalysis.structure.huGua && mhAnalysis.structure.huGua.hidden) {
                p.dims.meihua.huHidden = mhAnalysis.structure.huGua.hidden.cat + '：' + mhAnalysis.structure.huGua.hidden.desc;
              }
              if (mhAnalysis.structure.bianGua && mhAnalysis.structure.bianGua.trend) {
                p.dims.meihua.bianTrend = mhAnalysis.structure.bianGua.trend.type + '：' + mhAnalysis.structure.bianGua.trend.desc;
              }
            }
          }
        } catch (e) {
          console.warn('[buildPayload] meihua enrichment error:', e);
        }
      }

      // ═══ 4. 八字更多細節 ═══
      if (typeof S !== 'undefined' && S.bazi) {
        var bz = S.bazi;
        p.dims.bazi = p.dims.bazi || {};
        if (bz.dayun) {
          var dy = bz.dayun.find(function(d) { return d.isCurrent; });
          if (dy) {
            p.dims.bazi.dyDetail = dy.gz + '（' + (dy.level || '') + '，' + (dy.el || '') + '）';
            var yr = new Date().getFullYear();
            if (dy.liuNian) {
              var ln = dy.liuNian.find(function(l) { return l.year === yr; });
              if (ln) p.dims.bazi.lnDetail = ln.year + '年 ' + ln.gz + '（' + (ln.level || '') + '）';
              var lnNext = dy.liuNian.find(function(l) { return l.year === yr + 1; });
              if (lnNext) p.dims.bazi.lnNext = lnNext.year + '年 ' + lnNext.gz + '（' + (lnNext.level || '') + '）';
            }
          }
        }
        if (typeof bz.strongPercent === 'number') {
          p.dims.bazi.strongPercent = bz.strongPercent;
        }
      }

      // ═══ 5. 塔羅送更多牌面（7張關鍵位置）═══
      if (typeof S !== 'undefined' && S.tarot && S.tarot.drawn && S.tarot.drawn.length >= 10) {
        var tarotIdx = [0, 1, 2, 3, 4, 5, 9];
        var posNames = ['現況', '阻礙/交叉', '表意識/目標', '潛意識', '過去', '近未來', '最終結果'];
        p.dims.tarot = tarotIdx.map(function(i, idx) {
          var c = S.tarot.drawn[i];
          if (!c) return null;
          return { pos: posNames[idx] || ('P' + (i + 1)), name: c.name || c.n || '', rev: !c.isUp };
        }).filter(Boolean);
      }

      // ═══ 6. 紫微加入四化資訊 ═══
      if (typeof S !== 'undefined' && S.ziwei && S.ziwei.palaces) {
        p.dims.ziwei = p.dims.ziwei || {};
        try {
          var huaStars = [];
          S.ziwei.palaces.forEach(function(pal, idx) {
            if (!pal || !pal.stars) return;
            var palName = ['命宮','兄弟宮','夫妻宮','子女宮','財帛宮','疾厄宮','遷移宮','交友宮','官祿宮','田宅宮','福德宮','父母宮'][idx] || ('宮' + idx);
            pal.stars.forEach(function(star) {
              if (star.hua) huaStars.push(star.name + star.hua + '入' + palName);
            });
          });
          if (huaStars.length) p.dims.ziwei.sihua = huaStars.slice(0, 6);
        } catch (e) {}
      }

      // ═══ 7. 能量推薦 ═══
      var energy = (typeof buildSevenEnergyRecommendation === 'function')
        ? buildSevenEnergyRecommendation(ft, q) : null;
      if (energy) p.energyRecommendation = energy;

      // ═══ 8. 總標籤（verdict 層）═══
      if (typeof S !== 'undefined' && S._uResult && S._uResult.comb) {
        p.verdict = S._uResult.comb.finalDir;
        p.topTags = (S._uResult.comb.topTags || []).slice(0, 5).map(function(t) {
          return t.direction + ':' + t.tag;
        });
      }

    } catch (e) {
      console.warn('[buildPayload v2] error:', e.message);
      p.energyRecommendation = p.energyRecommendation || { rationale: ['推薦建立失敗：' + e.message], picks: [] };
    }
    return p;
  };

  function _renderAIEnergyCard(energy){ return "";
    if(!energy) return '';
    var html = '<div style="margin-top:1rem;padding:.9rem 1rem;background:linear-gradient(135deg,rgba(212,175,55,.08),rgba(255,255,255,.02));border:1px solid rgba(212,175,55,.18);border-radius:12px">';
    html += '<div style="font-size:.92rem;font-weight:700;color:var(--c-gold);margin-bottom:.45rem">💎 依你的命盤與這次問題，較適合的能量方向</div>';
    if(energy.warmText) html += '<div style="font-size:.88rem;line-height:1.85;color:var(--c-text);margin-bottom:.45rem">'+energy.warmText.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')+'</div>';
    html += '<div style="font-size:.8rem;line-height:1.8;color:var(--c-text-dim)">';
    if(energy.firstYongshen) html += '第一用神：'+energy.firstYongshen+'。 ';
    if(energy.secondYongshen) html += '第二用神：'+energy.secondYongshen+'。 ';
    if(energy.primaryNeedLabel) html += '本題主需求：'+energy.primaryNeedLabel+'。 ';
    if(energy.secondaryNeedLabel) html += '次需求：'+energy.secondaryNeedLabel+'。 ';
    if(energy.avoid && energy.avoid.length) html += '忌神避開：'+energy.avoid.join('、')+'。';
    html += '</div>';
    if(energy.picks && energy.picks.length){
      html += '<div style="margin-top:.75rem">';
      energy.picks.slice(0,3).forEach(function(p, idx){
        html += '<a href="'+(p.shopee||'https://tw.shp.ee/2n5Mo2w')+'" target="_blank" rel="noopener" class="inline-crystal" style="margin-top:'+(idx? '8px':'0')+'">'
          + '<span class="inline-crystal-icon">'+(typeof getProductSVG==='function'?getProductSVG(p.cat||'手鍊', p.name||''):'💎')+'</span>'
          + '<div class="inline-crystal-info"><div class="inline-crystal-name">'+(p.name||'能量手鍊')+'</div><div class="inline-crystal-desc">'+((p.desc||'').substring(0,34) + ((p.desc||'').length>34?'…':''))+'</div></div>'
          + '<span class="inline-crystal-price">'+(p.price||'')+'</span><i class="fas fa-chevron-right inline-crystal-arrow"></i></a>';
      });
      html += '</div>';
    }
    html += '</div>';
    return html;
  }

  function _cleanAIText(v){
    var s = _aiTxt(v || '');
    s = s.replace(/\*\*/g,'').replace(/^[\s\-—]+|[\s\-—]+$/g,'').trim();
    s = s.replace(/\n{3,}/g,'\n\n');
    return s;
  }

  function _isTooThinAIText(v){
    var s = _cleanAIText(v);
    if(!s) return true;
    if(s.length <= 3) return true;
    if(/^[你我他她它]$/.test(s)) return true;
    if(/^[，。！？、；：…]+$/.test(s)) return true;
    return false;
  }

  function _escapeAIHtml(v){
    var s = _cleanAIText(v);
    s = s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    s = s.split('\n\n').join('<br><br>');
    s = s.split('\n').join('<br>');
    return s;
  }

  function _renderAIResultObject(r){
    // ═══ v3 格式偵測：有 directAnswer 或 (有 answer 但沒有 consensus) = v3 ═══
    var isV3 = !!(r.directAnswer || (r.answer && !r.consensus));

    var html = '<div class="card" style="margin-top:.5rem;margin-bottom:6rem">';

    if(isV3){
      // ══════════════════════════════════════════
      // v3 渲染：直接回答 + 對話式展開，統一風格
      // ══════════════════════════════════════════
      html += '<div style="display:flex;align-items:center;gap:.4rem;margin-bottom:1rem"><span style="font-size:1.1rem">🌙</span><span style="font-size:.95rem;font-weight:700;color:var(--c-gold)">靜月之光・為你解讀</span></div>';

      function _safeHtml(s){
        return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
      }

      // ── directAnswer：金色粗體，不加框 ──
      var directAns = (r.directAnswer || '').replace(/\*\*/g,'').trim();
      if(directAns && directAns.length >= 5){
        html += '<div style="margin-bottom:1.2rem;padding:0 .2rem">';
        html += '<div style="font-size:1.1rem;line-height:1.9;font-weight:700;color:var(--c-gold-pale,#f5e6b8)">' + _safeHtml(directAns) + '</div>';
        html += '</div>';
      }

      // ── 主回答：保留 \n\n 拆段 ──
      var ansRaw = (r.answer || '').replace(/\*\*/g,'').trim();
      ansRaw = ansRaw.replace(/\\n\\n/g, '\n\n').replace(/\\n/g, '\n');
      var paragraphs = ansRaw.split(/\n\n+/).filter(function(p){ return p.trim().length > 0; });

      // 如果分段失敗（只有1段但超長），按句號分段
      if(paragraphs.length <= 1 && ansRaw.length > 300){
        var sentences = ansRaw.split(/(?<=[。！？])\s*/);
        paragraphs = [];
        var buf = '';
        for(var si = 0; si < sentences.length; si++){
          buf += sentences[si];
          if(buf.length >= 120 || si === sentences.length - 1){
            paragraphs.push(buf);
            buf = '';
          }
        }
      }

      // 所有段落統一：無邊框，純文字段落，靠間距呼吸
      for(var pi = 0; pi < paragraphs.length; pi++){
        html += '<div style="margin-bottom:1rem;padding:0 .2rem">';
        html += '<div style="font-size:.95rem;line-height:2;color:var(--c-text)">' + _safeHtml(paragraphs[pi]) + '</div>';
        html += '</div>';
      }

      // ── timing 段落 ──
      var timingRaw = (r.timing || '').replace(/\*\*/g,'').trim().replace(/\\n/g, '\n');
      if(timingRaw && timingRaw.length >= 10){
        html += '<div style="margin-top:.5rem;margin-bottom:.85rem;padding:.8rem 1rem;background:rgba(212,175,55,.05);border-left:3px solid var(--c-gold);border-radius:10px">';
        html += '<div style="font-size:.72rem;color:var(--c-gold);font-weight:700;margin-bottom:.3rem">⏳ 時機判斷</div>';
        html += '<div style="font-size:.9rem;line-height:1.85;color:var(--c-text)">' + _safeHtml(timingRaw) + '</div>';
        html += '</div>';
      }

      // ── 能量推薦 ──
      html += _renderAIEnergyCard(r.support_energy || r.energyRecommendation || r.energy || null);

      // ── oneliner 一句話總結 ──
      var oneRaw = (r.oneliner || r.summary || '').replace(/\*\*/g,'').trim();
      if(oneRaw && oneRaw.length >= 5){
        html += '<div style="margin-top:1rem;padding:.9rem 1.1rem;background:linear-gradient(135deg,rgba(212,175,55,.08),rgba(139,92,246,.05));border-radius:12px;border:1px solid rgba(212,175,55,.2);text-align:center">';
        html += '<div style="font-size:1.05rem;line-height:1.85;color:var(--c-gold);font-weight:700">' + _safeHtml(oneRaw) + '</div>';
        html += '</div>';
      }

    } else {
      // ══════════════════════════════════════════
      // v2 渲染（向後兼容）：answer + consensus + conflict + strategy + timing + summary
      // ══════════════════════════════════════════
      html += '<div style="display:flex;align-items:center;gap:.4rem;margin-bottom:.8rem"><span style="font-size:1.1rem">🌙</span><span style="font-size:.95rem;font-weight:700;color:var(--c-gold)">我陪你把這題慢慢說清楚</span></div>';

      if(r.answer || r.core_answer){
        var ansText2 = _aiTxt(r.answer||r.core_answer);
        var ansHtml2 = ansText2.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        ansHtml2 = ansHtml2.replace(/\n\n/g,'<br><br>').replace(/\n/g,'<br>');
        html += '<div class="ai-spotlight" style="margin-bottom:.8rem;padding:1rem 1.2rem;background:rgba(212,175,55,.06);border-left:3px solid var(--c-gold);border-radius:12px"><div style="display:inline-block;font-size:.65rem;font-weight:700;color:var(--c-gold);background:rgba(212,175,55,.12);border:1px solid rgba(212,175,55,.25);border-radius:20px;padding:2px 10px;margin-bottom:.4rem;letter-spacing:.05em">✦ 看這裡</div><div style="font-size:.74rem;color:var(--c-gold);font-weight:700;margin-bottom:.25rem">🌙 我先直接跟你說</div><div style="font-size:.95rem;line-height:1.9;font-weight:600;color:var(--c-gold-pale,#f5e6b8)">'+ansHtml2+'</div></div>';
      }

      var sectionMap = [
        ['consensus','✨ 多系統交集','#8b5cf6'],
        ['conflict','🍂 阻力與變數','#f87171'],
        ['strategy','🕯️ 你現在可以先這樣做','#4ade80'],
        ['timing','⏳ 時機提醒','var(--c-gold)']
      ];
      sectionMap.forEach(function(item){
        var val = r[item[0]];
        if(!val || val === 'null' || val === null) return;
        var body = Array.isArray(val) ? val.join('；') : _cleanAIText(val);
        if(_isTooThinAIText(body)) return;
        html += '<div class="content-secondary" style="margin-bottom:.8rem;padding:.65rem .85rem;background:rgba(255,255,255,.02);border-left:3px solid '+item[2]+';border-radius:8px"><div style="font-size:.72rem;color:'+item[2]+';font-weight:700;margin-bottom:.25rem">'+item[1]+'</div><div style="font-size:.9rem;line-height:1.85">'+_escapeAIHtml(body)+'</div></div>';
      });

      html += _renderAIEnergyCard(r.support_energy || r.energyRecommendation || r.energy || null);

      if(!_isTooThinAIText(r.summary) && _cleanAIText(r.summary).length >= 10){
        html += '<div style="margin-top:.85rem;text-align:center;color:var(--c-gold);font-weight:700;line-height:1.9;font-size:.95rem">'+_escapeAIHtml(r.summary)+'</div>';
      }
    }

    html += '</div>';
    return html;
  }

  _triggerAIDeep = async function() {
    var btn = document.getElementById('ai-deep-btn');
    var resultDiv = document.getElementById('ai-deep-result');
    if (!btn || !resultDiv) return;
    var admin = _aiIsAdmin();
    btn.disabled = true;
    btn.innerHTML = '☽ 正在翻閱你的命盤…';
    btn.style.opacity = '0.6';
    btn.style.cursor = 'wait';
    resultDiv.style.display = 'block';
    try{ var sticky=document.getElementById('sticky-cta'); if(sticky){ sticky.classList.remove('visible'); sticky.style.display='none'; } }catch(_e){}
    resultDiv.innerHTML = '<div style="text-align:center;padding:2rem 1.5rem">' +
      '<div style="position:relative;width:60px;height:60px;margin:0 auto .8rem">' +
        '<div style="position:absolute;inset:0;border:2px solid rgba(212,175,55,.1);border-radius:50%"></div>' +
        '<div style="position:absolute;inset:0;border:2px solid transparent;border-top-color:var(--c-gold,#d4af37);border-radius:50%;animation:spin 1.2s linear infinite"></div>' +
        '<div style="position:absolute;inset:6px;border:2px solid transparent;border-bottom-color:rgba(139,92,246,.5);border-radius:50%;animation:spin 2s linear infinite reverse"></div>' +
        '<div style="position:absolute;inset:50%;transform:translate(-50%,-50%);font-size:1.2rem">☽</div>' +
      '</div>' +
      '<div style="font-size:.92rem;color:var(--c-gold);font-weight:600;margin-bottom:.3rem">正在為你翻閱命盤…</div>' +
      '<div id="ai-loading-phase" style="font-size:.78rem;color:var(--c-text-dim);transition:opacity .3s">交叉比對七套系統中</div>' +
      '</div>';
    // ── loading 階段文字輪播 ──
    var _aiLoadPhases = ['交叉比對七套系統中', '閱讀八字與紫微命盤…', '解讀梅花易數卦象…', '翻閱塔羅牌面訊息…', '對照西洋與吠陀星盤…', '整合交叉訊號，找出關鍵…', '正在為你組織語言…'];
    var _aiPhaseIdx = 0;
    var _aiPhaseTimer = setInterval(function(){
      _aiPhaseIdx++;
      if(_aiPhaseIdx >= _aiLoadPhases.length) _aiPhaseIdx = _aiLoadPhases.length - 1;
      var el = document.getElementById('ai-loading-phase');
      if(el){ el.style.opacity = '0'; setTimeout(function(){ if(el){ el.textContent = _aiLoadPhases[_aiPhaseIdx]; el.style.opacity = '1'; }}, 300); }
    }, 3500);
    try {
      var payload = _buildPayload();
      var body = { payload: payload };
      if (window._JY_ADMIN_TOKEN) {
        // 僅透過 token 認證，不送明文個資
        body.admin_token = window._JY_ADMIN_TOKEN || '';
      }
      var resp = await fetch(AI_WORKER_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
      var data = await resp.json();
      clearInterval(_aiPhaseTimer);
      if (!resp.ok) throw Object.assign({status:resp.status}, data);
      if (!admin) _aiMarkUsed();
      var r = data.result;
      if (!r) throw new Error('回傳為空');
      if (typeof r === 'object' && r !== null) {
        if (!r.support_energy && payload.energyRecommendation) r.support_energy = payload.energyRecommendation;
        var resultHtml = _renderAIResultObject(r);
        // Admin usage info: append inside the card
        if (admin && data.usage) {
          resultHtml = resultHtml.replace(/<\/div>$/, '<div style="font-size:.58rem;color:var(--c-text-dim);margin-top:.6rem;opacity:.3;text-align:right">[Admin] In:'+data.usage.input_tokens+' Out:'+data.usage.output_tokens+' ≈$'+(data.usage.input_tokens*3/1e6+data.usage.output_tokens*15/1e6).toFixed(4)+'</div></div>');
        }
        // Admin: show readings debug
        if (admin) {
          try {
            var _dr = Object.keys(payload.readings||{});
            var _ds = _dr.map(function(k){var v=payload.readings[k]; return k+':'+(typeof v==='string'?v.length:JSON.stringify(v||'').length);});
            var _dt = JSON.stringify(payload).length;
            resultHtml = resultHtml.replace(/<\/div>$/, '<div style="font-size:.55rem;color:#a78bfa;margin-top:.3rem;opacity:.5;word-break:break-all">[payload] '+_dt+'字 | readings: '+_ds.join(', ')+'</div></div>');
          } catch(e){}
        }
        resultDiv.innerHTML = resultHtml;
      } else {
        var html = '<div class="card" style="border-left:3px solid #8b5cf6;margin-top:.5rem"><div style="display:flex;align-items:center;gap:.4rem;margin-bottom:.8rem"><span style="font-size:1.1rem">🌙</span><span style="font-size:.95rem;font-weight:700;color:var(--c-gold)">靜月之光・為你解讀</span></div>';
        var txt = String(r||'');
        // 移除【】標記，自然段落渲染
        var cleanTxt = txt.replace(/【[^】]*】\s*/g, '').replace(/\n{3,}/g, '\n\n').trim();
        var paras = cleanTxt.split(/\n\n+/);
        paras.forEach(function(para, idx) {
          para = para.trim(); if (!para) return;
          var escaped = para.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
          if (idx === 0) {
            html += '<div style="font-size:1rem;font-weight:600;line-height:1.9;color:var(--c-gold-pale,#f5e6b8);margin-bottom:.8rem">' + escaped + '</div>';
          } else {
            html += '<div style="font-size:.92rem;line-height:1.9;color:var(--c-text,#e0d8c8);margin-bottom:.7rem">' + escaped + '</div>';
          }
        });
        html += _renderAIEnergyCard(payload.energyRecommendation);
        if (admin && data.usage) html += '<div style="font-size:.58rem;color:var(--c-text-dim);margin-top:.6rem;opacity:.3;text-align:right">[Admin] In:'+data.usage.input_tokens+' Out:'+data.usage.output_tokens+' ≈$'+(data.usage.input_tokens*3/1e6+data.usage.output_tokens*15/1e6).toFixed(4)+'</div>';
        html += '</div>';
        resultDiv.innerHTML = html;
      }
      btn.innerHTML = '✅ 已替你整理完成';
      btn.style.background = 'rgba(74,222,128,.1)';
      btn.style.borderColor = 'rgba(74,222,128,.3)';
      btn.style.color = '#4ade80';
      btn.style.boxShadow = 'none';
    } catch(err) {
      clearInterval(_aiPhaseTimer);
      console.error('[AI]', err);
      if (err.status === 429 && !admin) {
        // Server confirmed rate limited — re-sync localStorage
        try{ _aiMarkUsed(); }catch(_e){}
        btn.innerHTML = '🔒 今日解讀已使用';
        btn.style.opacity = '0.4';
        btn.disabled = true;
        btn.style.pointerEvents = 'none';
        resultDiv.innerHTML = '<div style="text-align:center;padding:.8rem;color:var(--c-gold);font-size:.82rem">今天這題已看過・00:00 後可再看 1 次</div>';
      } else {
        btn.disabled = false;
        btn.innerHTML = admin ? '🔮 重試（Admin）' : '🔮 重試深度解讀';
        btn.style.opacity = '1';
        btn.style.cursor = 'pointer';
        btn.style.pointerEvents = 'auto';
        resultDiv.innerHTML = '<div style="text-align:center;padding:.8rem;color:#f87171;font-size:.8rem">' +
          (admin && err.status === 429 ? 'Worker 429 但你是管理員，可重試' : '暫時無法使用，請稍後再試') +
          (admin ? '<br><span style="font-size:.6rem;opacity:.4">[Debug] '+(err.status||'')+' '+(err.error||err.detail||err.message||'')+'</span>' : '') + '</div>';
      }
    }
  };
})();
// ═══════════════════════════════════════════════════════════════
// 離線模式升級 v2：命盤摘要卡 + AI 英雄按鈕
// 修復：八字 [object Object]、清除分數下方裁決雜訊、API 觸發
// ═══════════════════════════════════════════════════════════════
(function() {
  'use strict';

  // ══ 安全取柱字串（pillars 可能是 {天干,地支} 物件或純字串）══
  function _pillarStr(p) {
    if (!p) return '';
    if (typeof p === 'string') return p;
    if (typeof p === 'object') {
      var g = p.gan || p.天干 || p.stem || '';
      var z = p.zhi || p.地支 || p.branch || '';
      return g + z;
    }
    return String(p);
  }

  // ══ 工具：從 S 提取命盤摘要 ══
  function _getDataSnapshot() {
    var snap = { systems: [] };

    // 八字
    try { if (S.bazi) {
      var b = S.bazi, p = b.pillars;
      var line = '已排';
      if (p) {
        var parts = [];
        if (p.year) parts.push(_pillarStr(p.year));
        if (p.month) parts.push(_pillarStr(p.month));
        if (p.day) parts.push(_pillarStr(p.day));
        if (p.hour) parts.push(_pillarStr(p.hour));
        if (parts.length) line = parts.join('　');
      }
      var ex = [];
      if (b.dm) ex.push('日主 ' + b.dm);
      if (b.fav && b.fav.length) ex.push('喜 ' + (Array.isArray(b.fav) ? b.fav.join('') : b.fav));
      snap.systems.push({ name: '八字', icon: '☯', data: line, sub: ex.join('　') });
    }} catch(e) { console.warn('[Snap] bazi:', e); }

    // 紫微
    try { if (S.ziwei && S.ziwei.palaces) {
      var ming = S.ziwei.palaces[0];
      var stars = ming && ming.stars ? ming.stars.filter(function(s) { return s.type === 'major'; }).map(function(s) { return s.name; }).join('、') : '';
      var sub = [];
      if (S.ziwei.mingZhu) sub.push('命主 ' + S.ziwei.mingZhu);
      if (S.ziwei.wuxingJu) sub.push(S.ziwei.wuxingJu);
      snap.systems.push({ name: '紫微', icon: '⬡', data: stars ? '命宮：' + stars : '命盤已排', sub: sub.join('　') });
    }} catch(e) {}

    // 梅花
    try { if (S.meihua && S.meihua.ty) {
      var mh = S.meihua;
      snap.systems.push({ name: '梅花', icon: '☰', data: (mh.ben && mh.ben.n || '') + ' → ' + (mh.bian && mh.bian.n || ''), sub: '體用：' + (mh.ty.r || '') });
    }} catch(e) {}

    // 塔羅
    try { if (S.tarot && S.tarot.drawn && S.tarot.drawn.length >= 3) {
      var d = S.tarot.drawn;
      var cn = d.slice(0, 3).map(function(c) { return (c.name || c.n) + (c.isUp ? '↑' : '↓'); }).join('、');
      snap.systems.push({ name: '塔羅', icon: '✦', data: cn + (d.length > 3 ? ' …共' + d.length + '張' : ''), sub: '' });
    }} catch(e) {}

    // 西占
    try { if (S.natal && S.natal.planets) {
      var n = S.natal;
      var sun = n.planets['太陽'] ? n.planets['太陽'].sign : '';
      var moon = n.planets['月亮'] ? n.planets['月亮'].sign : '';
      var asc = n.ascSign ? n.ascSign.name : '';
      snap.systems.push({ name: '西占', icon: '☉', data: '☉' + sun + '　☽' + moon + '　ASC ' + asc, sub: '' });
    }} catch(e) {}

    // 吠陀
    try { if (S.jyotish) {
      var j = S.jyotish, pts = [];
      if (j.lagnaSign) pts.push('Lagna ' + j.lagnaSign);
      if (j.currentMD && j.currentMD.lord) pts.push('主運 ' + j.currentMD.lord);
      if (j.janmaNakshatra) pts.push('月宿 ' + (j.janmaNakshatra.zh || j.janmaNakshatra.en || ''));
      snap.systems.push({ name: '吠陀', icon: '🕉', data: pts.join('　'), sub: '' });
    }} catch(e) {}

    // 姓名
    try { if (S.nameResult) {
      var nr = S.nameResult;
      var lv = nr.sanCaiLevel || '';
      var rg = nr.renGe ? (nr.renGe.fortune ? nr.renGe.fortune.level : '') : '';
      snap.systems.push({ name: '姓名', icon: '📛', data: '三才 ' + lv + (rg ? '　人格 ' + rg : ''), sub: '' });
    }} catch(e) {}

    return snap;
  }

  // ══ 渲染命盤摘要卡 ══
  function _renderDataCard(snap) {
    var h = '';
    h += '<div style="display:flex;align-items:center;gap:.5rem;margin-bottom:.7rem">';
    h += '<span style="font-size:1.05rem">☽</span>';
    h += '<span style="font-size:.86rem;font-weight:700;color:var(--c-gold)">七套系統已計算完成</span>';
    h += '</div>';

    if (snap.systems.length) {
      h += '<div style="display:flex;flex-direction:column;gap:.4rem;margin-bottom:.8rem">';
      snap.systems.forEach(function(sys) {
        h += '<div style="display:flex;align-items:baseline;gap:.5rem;padding:.3rem .5rem;background:rgba(255,255,255,.025);border-radius:6px;border-left:2px solid rgba(212,175,55,.3)">';
        h += '<span style="font-size:.73rem;min-width:2.6rem;color:var(--c-gold);font-weight:600">' + sys.icon + ' ' + sys.name + '</span>';
        h += '<span style="font-size:.8rem;color:var(--c-text,#e0d8c8)">' + sys.data + '</span>';
        if (sys.sub) h += '<span style="font-size:.7rem;color:var(--c-text-dim);margin-left:auto;white-space:nowrap">' + sys.sub + '</span>';
        h += '</div>';
      });
      h += '</div>';
    }

    // 交叉信號標籤
    try { if (S._uResult && S._uResult.comb && S._uResult.comb.topTags && S._uResult.comb.topTags.length) {
      var tags = S._uResult.comb.topTags.slice(0, 4);
      h += '<div style="display:flex;flex-wrap:wrap;gap:.3rem;margin-bottom:.7rem">';
      tags.forEach(function(t) {
        var c = t.direction === 'pos' ? 'rgba(74,222,128,.7)' : t.direction === 'neg' ? 'rgba(248,113,113,.7)' : 'rgba(251,191,36,.7)';
        var bg = t.direction === 'pos' ? 'rgba(74,222,128,.08)' : t.direction === 'neg' ? 'rgba(248,113,113,.08)' : 'rgba(251,191,36,.08)';
        h += '<span style="display:inline-block;padding:2px 7px;border-radius:10px;font-size:.68rem;color:' + c + ';background:' + bg + ';border:1px solid ' + c.replace(',.7)', ',.2)') + '">' +
          (t.direction === 'pos' ? '↑' : t.direction === 'neg' ? '↓' : '~') + ' ' + t.tag + '</span>';
      });
      h += '</div>';
    }} catch(e) {}

    h += '<div style="border-top:1px solid rgba(212,175,55,.15);margin:.5rem 0"></div>';
    h += '<div style="text-align:center;padding:.2rem 0">';
    h += '<p style="font-size:.84rem;color:var(--c-text-dim);margin:0 0 .15rem;line-height:1.6">數據已備齊，讓靜月老師幫你整合解讀</p>';
    h += '<p style="font-size:.7rem;color:var(--c-text-muted);margin:0">七套系統的結果，由靜月老師翻譯成你聽得懂的答案</p>';
    h += '</div>';
    return h;
  }

  // ══ 渲染 AI 英雄按鈕 ══
  function _renderHeroBtn(admin, used) {
    var h = '';
    h += '<div style="text-align:center;padding:.8rem 0 .3rem">';
    h += '<button id="ai-deep-btn" onclick="_triggerAIDeep()" style="' +
      'display:inline-flex;align-items:center;justify-content:center;gap:.5rem;' +
      'width:100%;max-width:340px;' +
      'background:linear-gradient(135deg,rgba(139,92,246,.25),rgba(212,175,55,.18),rgba(139,92,246,.12));' +
      'color:#fff;border:2px solid rgba(212,175,55,.5);' +
      'padding:1.1rem 2rem;border-radius:14px;font-size:1.05rem;font-weight:700;' +
      'cursor:pointer;transition:all .3s;font-family:inherit;' +
      'box-shadow:0 4px 24px rgba(139,92,246,.3),0 2px 10px rgba(212,175,55,.15);' +
      'letter-spacing:.05em;' +
      (used ? 'opacity:.4;pointer-events:none;' : 'animation:ai-hero-glow 2.5s ease-in-out infinite;') + '" ' +
      (used ? 'disabled' : '') + '>' +
      (used ? '🔒 今日解讀已開啟' : '<span style="font-size:1.2rem">🌙</span> 開啟深層解讀') +
    '</button>';
    h += '<div style="font-size:.7rem;color:var(--c-text-dim);margin-top:.45rem;opacity:.55">' +
      (admin ? '👑 管理員模式・無限次' : used ? '每人每日 1 次・剩餘 0 次・00:00 重置' : '✦ 免費・每人每日 1 次') +
    '</div></div>';
    h += '<style>@keyframes ai-hero-glow{0%,100%{box-shadow:0 4px 24px rgba(139,92,246,.3),0 2px 10px rgba(212,175,55,.15)}50%{box-shadow:0 8px 36px rgba(139,92,246,.5),0 4px 16px rgba(212,175,55,.3)}}</style>';
    h += '<div id="ai-deep-result" style="display:none"></div>';
    return h;
  }

  // ══ 清除分數下方的裁決雜訊（用戶不需要看內部邏輯）══
  function _cleanVerdictNoise() {
    // 裁決面板（一致訊號、矛盾訊號、裁決規則、可信度、關鍵訊號、問題專屬分析）
    var arbEl = document.getElementById('r-verdict-arbitration');
    if (arbEl) arbEl.innerHTML = '';

    // vnote（偏凶 有轉機 之類的文字保留在環形圖裡已足夠）
    // 風險提示保留（Sade Sati 等真正有意義的提醒）

    // r-verdict-sources 下方的 mini-mh 也清掉（太細節）
    var miniMh = document.getElementById('r-verdict-mini-mh');
    if (miniMh) miniMh.innerHTML = '';
  }

  // ══ AI 成功後隱藏離線區塊（避免矛盾）══
  function _hideOfflineSections() {
    // 1. 環形分數區（verdict ring + 各系統小數字 + 風險提示）
    var verdictEl = document.getElementById('r-verdict');
    if (verdictEl) verdictEl.style.display = 'none';

    // 2. 問題回顯（已在 AI 回答內自帶上下文）
    var qHero = document.getElementById('r-question-hero');
    if (qHero) qHero.style.display = 'none';

    // 3.「你現在可以做的事」（離線行動建議，跟 AI 脫節）
    var actionCard = document.getElementById('action-card');
    if (actionCard) actionCard.style.display = 'none';

    // 4.「為什麼這樣判斷」（離線裁決邏輯）
    //    它是 r-answer 卡片後面的第二個 collapsible-card
    var collapsibles = document.querySelectorAll('#step-3 .collapsible-card');
    collapsibles.forEach(function(card) {
      var title = card.querySelector('.card-title');
      if (!title) return;
      var text = title.textContent || '';
      // 隱藏「為什麼這樣判斷」和「命理詳細分析」— AI 已整合所有資訊
      if (text.indexOf('為什麼') !== -1 || text.indexOf('命理詳細') !== -1) {
        card.style.display = 'none';
      }
    });

    // 5. 可能性進度條（r-pfill 等）已在「為什麼這樣判斷」裡面，隨父元素隱藏

    // 6. quick-shop（推薦水晶簡化版 — 跟完整水晶處方重複）
    var qsEl = document.getElementById('quick-shop');
    if (qsEl) qsEl.style.display = 'none';
    // 7. quick-shop 保留（商業 CTA）— 已隱藏
    // 8. feedback 保留

    // 9. 「想再測一次」— API 模式下不提供重複測試（額度限制）
    var shareGate = document.getElementById('share-gate');
    if (shareGate) shareGate.style.display = 'none';
    // discount-reveal（折扣碼）
    var discountReveal = document.getElementById('discount-reveal');
    if (discountReveal) discountReveal.style.display = 'none';

    // 10. 分享存圖 + 趣味功能 → 保留（曝光管道 + 互動黏性）
  }

  // ══ 覆寫 _injectAIButton — 隱藏所有離線區塊 + 自動觸發 AI ══
  _injectAIButton = function() {
    var answerEl = document.getElementById('r-answer');
    var wrapEl = document.getElementById('ai-deep-wrap');
    if (!answerEl) return;

    var admin = _aiIsAdmin();
    var used = !admin && _aiUsedToday();

    // 保存離線回答（供 Google Forms 通知）
    var txt = answerEl.innerText || '';
    if (txt.length > 5) answerEl.setAttribute('data-offline-answer', txt.substring(0, 800));

    // ── 立即隱藏所有離線區塊 ──
    _hideOfflineSections();
    _cleanVerdictNoise();
    if (wrapEl) wrapEl.style.display = 'none';

    if (used) {
      // ── 額度已用：顯示提示，不觸發 API ──
      answerEl.innerHTML =
        '<div style="text-align:center;padding:2rem 1rem">' +
          '<div style="font-size:2.5rem;margin-bottom:.8rem">🌙</div>' +
          '<div style="font-size:1rem;font-weight:700;color:var(--c-gold);margin-bottom:.5rem">今日免費解讀已使用</div>' +
          '<div style="font-size:.85rem;color:var(--c-text-dim);line-height:1.7;margin-bottom:.3rem">每人每天可免費解讀 1 次</div>' +
          '<div style="font-size:.78rem;color:var(--c-text-muted)">午夜 00:00 自動重置</div>' +
        '</div>';
    } else {
      // ── 尚有額度：顯示華麗 loading + 自動觸發 AI ──
      answerEl.innerHTML = _renderAILoading();

      // 隱藏的按鈕（供 _triggerAIDeep 內部找到）
      var hiddenBtn = document.createElement('button');
      hiddenBtn.id = 'ai-deep-btn';
      hiddenBtn.style.display = 'none';
      answerEl.appendChild(hiddenBtn);
      var hiddenResult = document.createElement('div');
      hiddenResult.id = 'ai-deep-result';
      hiddenResult.style.display = 'none';
      answerEl.appendChild(hiddenResult);

      // 延遲一小段讓 DOM 穩定，然後自動呼叫 AI
      setTimeout(function() {
        _triggerAIDeep();
      }, 600);
    }
  };

  // ══ 華麗 AI 載入動畫 ══
  function _renderAILoading() {
    return '<div style="text-align:center;padding:2.5rem 1rem">' +
      // 月亮 + 環形動畫
      '<div style="position:relative;width:80px;height:80px;margin:0 auto 1.2rem">' +
        '<div style="position:absolute;inset:0;border:2px solid rgba(212,175,55,.08);border-radius:50%"></div>' +
        '<div style="position:absolute;inset:0;border:2.5px solid transparent;border-top-color:var(--c-gold,#d4af37);border-radius:50%;animation:spin 1.5s linear infinite"></div>' +
        '<div style="position:absolute;inset:8px;border:2px solid transparent;border-bottom-color:rgba(139,92,246,.4);border-radius:50%;animation:spin 2.5s linear infinite reverse"></div>' +
        '<div style="position:absolute;inset:18px;border:1.5px solid transparent;border-left-color:rgba(212,175,55,.3);border-radius:50%;animation:spin 3.5s linear infinite"></div>' +
        '<div style="position:absolute;inset:50%;transform:translate(-50%,-50%);font-size:1.6rem;filter:drop-shadow(0 0 8px rgba(212,175,55,.4))">🌙</div>' +
      '</div>' +
      // 主標題
      '<div style="font-size:1rem;color:var(--c-gold);font-weight:700;margin-bottom:.4rem;letter-spacing:.05em">靜月老師正在翻閱你的命盤</div>' +
      // 階段文字
      '<div id="ai-loading-phase" style="font-size:.82rem;color:var(--c-text-dim);transition:opacity .4s;line-height:1.6">交叉比對七套系統中…</div>' +
      // 系統列表（逐步點亮）
      '<div id="ai-loading-systems" style="display:flex;justify-content:center;gap:.6rem;margin-top:1rem;flex-wrap:wrap">' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">☯ 八字</span>' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">⬡ 紫微</span>' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">☰ 梅花</span>' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">✦ 塔羅</span>' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">☉ 西占</span>' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">🕉 吠陀</span>' +
        '<span class="ai-sys-dot" style="opacity:.3;font-size:.7rem;color:var(--c-text-dim);transition:all .5s">📛 姓名</span>' +
      '</div>' +
    '</div>';
  }

  // ══ 覆寫 _triggerAIDeep — AI 結果直接寫回 r-answer ══
  _triggerAIDeep = async function() {
    var btn = document.getElementById('ai-deep-btn');
    var resultDiv = document.getElementById('ai-deep-result');
    // btn 可能是隱藏的（自動觸發模式）
    var admin = _aiIsAdmin();

    try { var sticky = document.getElementById('sticky-cta'); if (sticky) { sticky.classList.remove('visible'); sticky.style.display = 'none'; } } catch(_e) {}

    // ── loading 階段：逐步點亮系統 + 文字輪播 ──
    var phases = [
      { text: '閱讀八字命盤…', dotIdx: 0 },
      { text: '排列紫微斗數…', dotIdx: 1 },
      { text: '解讀梅花卦象…', dotIdx: 2 },
      { text: '翻閱塔羅牌面…', dotIdx: 3 },
      { text: '對照西洋星盤…', dotIdx: 4 },
      { text: '比對吠陀占星…', dotIdx: 5 },
      { text: '整合姓名能量…', dotIdx: 6 },
      { text: '交叉驗證，找出關鍵…', dotIdx: -1 },
      { text: '正在為你組織語言…', dotIdx: -1 }
    ];
    var pi = 0;
    var pt = setInterval(function() {
      pi++;
      if (pi >= phases.length) pi = phases.length - 1;
      var phase = phases[pi];
      var el = document.getElementById('ai-loading-phase');
      if (el) {
        el.style.opacity = '0';
        setTimeout(function() {
          if (el) { el.textContent = phase.text; el.style.opacity = '1'; }
        }, 300);
      }
      // 點亮對應的系統 dot
      if (phase.dotIdx >= 0) {
        var dots = document.querySelectorAll('.ai-sys-dot');
        if (dots[phase.dotIdx]) {
          dots[phase.dotIdx].style.opacity = '1';
          dots[phase.dotIdx].style.color = 'var(--c-gold,#d4af37)';
          dots[phase.dotIdx].style.fontWeight = '700';
        }
      }
    }, 2200);

    try {
      var payload = _buildPayload();
      var body = { payload: payload };
      if (window._JY_ADMIN_TOKEN) body.admin_token = window._JY_ADMIN_TOKEN;
      var resp = await fetch(AI_WORKER_URL, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
      var data = await resp.json();
      clearInterval(pt);
      if (!resp.ok) throw Object.assign({ status: resp.status }, data);
      if (!admin) _aiMarkUsed();

      var r = data.result;
      if (!r) throw new Error('回傳為空');

      var answerEl = document.getElementById('r-answer');
      if (!answerEl) return;

      function _esc(s) { return s ? String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') : ''; }

      var ai = '';
      ai += '<div class="ai-spotlight" style="padding:1.2rem;border-radius:14px">';
      ai += '<div style="display:flex;align-items:center;gap:.4rem;margin-bottom:.8rem">';
      ai += '<span style="font-size:1.1rem">🌙</span>';
      ai += '<span style="font-size:.92rem;font-weight:700;color:var(--c-gold)">靜月之光・為你解讀</span>';
      if (admin && data.usage) ai += '<span style="font-size:.55rem;color:var(--c-text-dim);margin-left:auto;opacity:.4">[' + data.usage.input_tokens + 'in/' + data.usage.output_tokens + 'out ≈$' + (data.usage.input_tokens * 3 / 1e6 + data.usage.output_tokens * 15 / 1e6).toFixed(4) + ']</span>';
      ai += '</div>';

      if (typeof r === 'object' && r !== null) {
        if (r.directAnswer) {
          ai += '<div style="font-size:1.1rem;font-weight:700;line-height:1.7;color:var(--c-gold-pale,#f5e6b8);margin-bottom:.8rem;padding-bottom:.6rem;border-bottom:1px solid rgba(212,175,55,.15)">' + _esc(r.directAnswer) + '</div>';
        }
        var mainText = r.answer || '';
        if (mainText) {
          mainText.split(/\n\n+/).forEach(function(para, idx) {
            para = para.trim(); if (!para) return;
            var escaped = para.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br>');
            if (idx === 0 && !r.directAnswer) {
              ai += '<div style="font-size:1.02rem;font-weight:600;line-height:1.9;color:var(--c-gold-pale,#f5e6b8);margin-bottom:.7rem">' + escaped + '</div>';
            } else {
              ai += '<div style="font-size:.92rem;line-height:1.9;color:var(--c-text,#e0d8c8);margin-bottom:.6rem">' + escaped + '</div>';
            }
          });
        }
        if (r.timing) {
          ai += '<div style="margin-top:.5rem;padding:.5rem .7rem;background:rgba(251,191,36,.06);border-left:3px solid rgba(251,191,36,.4);border-radius:6px;font-size:.85rem;color:var(--c-text-dim);line-height:1.7"><span style="color:var(--c-gold);font-weight:600">⏳ 時機</span>　' + _esc(r.timing) + '</div>';
        }
        var closing = r.oneliner || r.summary || '';
        if (closing) {
          ai += '<div style="margin-top:.8rem;text-align:center;color:var(--c-gold);font-weight:700;line-height:1.8;font-size:.95rem">' + _esc(closing) + '</div>';
        }
      } else {
        var txt2 = String(r || '').replace(/【[^】]*】\s*/g, '').replace(/\n{3,}/g, '\n\n').trim();
        txt2.split(/\n\n+/).forEach(function(para, idx) {
          para = para.trim(); if (!para) return;
          var escaped = para.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br>');
          ai += '<div style="font-size:' + (idx === 0 ? '1rem' : '0.92rem') + ';' + (idx === 0 ? 'font-weight:600;color:var(--c-gold-pale,#f5e6b8)' : 'color:var(--c-text,#e0d8c8)') + ';line-height:1.9;margin-bottom:.6rem">' + escaped + '</div>';
        });
      }

      if (admin && data.symbols) {
        ai += '<details style="margin-top:.6rem"><summary style="font-size:.6rem;color:#a78bfa;opacity:.4;cursor:pointer">[Admin] Step1 Symbols</summary>';
        ai += '<pre style="font-size:.55rem;color:#a78bfa;opacity:.5;white-space:pre-wrap;max-height:200px;overflow:auto">' + JSON.stringify(data.symbols, null, 2).replace(/</g, '&lt;') + '</pre></details>';
      }
      if (admin) { try {
        var _rk = Object.keys(payload.readings || {});
        var _rs = _rk.map(function(k) { return k + ':' + JSON.stringify(payload.readings[k]).length; });
        ai += '<div style="font-size:.55rem;color:#a78bfa;margin-top:.3rem;opacity:.4;word-break:break-all">[payload] ' + JSON.stringify(payload).length + '字 | readings: ' + _rs.join(', ') + '</div>';
      } catch(e) {} }

      ai += '</div>';
      answerEl.innerHTML = ai;

      var parentCard = answerEl.closest('.card');
      if (parentCard) parentCard.style.borderLeftColor = 'rgba(139,92,246,.5)';

      // ══ AI 成功：隱藏所有離線模式區塊（避免跟 AI 回答矛盾）══
      _hideOfflineSections();

    } catch(err) {
      clearInterval(pt);
      console.error('[AI]', err);
      var answerEl2 = document.getElementById('r-answer');
      if (!answerEl2) return;
      if (err.status === 429 && !admin) {
        try { _aiMarkUsed(); } catch(_e) {}
        answerEl2.innerHTML =
          '<div style="text-align:center;padding:2rem 1rem">' +
            '<div style="font-size:2rem;margin-bottom:.6rem">🔒</div>' +
            '<div style="font-size:1rem;font-weight:700;color:var(--c-gold);margin-bottom:.4rem">今日免費解讀已使用</div>' +
            '<div style="font-size:.82rem;color:var(--c-text-dim)">午夜 00:00 重置・明天再來</div>' +
          '</div>';
      } else {
        answerEl2.innerHTML =
          '<div style="text-align:center;padding:2rem 1rem">' +
            '<div style="font-size:2rem;margin-bottom:.6rem">⚠️</div>' +
            '<div style="font-size:.95rem;color:var(--c-text-dim);margin-bottom:1rem">解讀暫時無法使用</div>' +
            (admin ? '<div style="font-size:.6rem;color:#f87171;opacity:.5;margin-bottom:.8rem">[Debug] ' + (err.status||'') + ' ' + (err.error||err.detail||err.message||'') + '</div>' : '') +
            '<button onclick="_triggerAIDeep()" style="' +
              'display:inline-flex;align-items:center;justify-content:center;gap:.4rem;' +
              'padding:.8rem 2rem;border-radius:12px;font-size:.92rem;font-weight:600;' +
              'background:linear-gradient(135deg,rgba(139,92,246,.2),rgba(212,175,55,.15));' +
              'color:var(--c-gold,#d4af37);border:1.5px solid rgba(212,175,55,.4);' +
              'cursor:pointer;font-family:inherit;transition:all .2s">' +
              '<span style="font-size:1.1rem">🌙</span> 重新嘗試' +
            '</button>' +
            // 隱藏的 btn+result 供 retry 用
            '<button id="ai-deep-btn" style="display:none"></button>' +
            '<div id="ai-deep-result" style="display:none"></div>' +
          '</div>';
      }
    }
  };

  // ══ 覆寫 generateResultCard — AI 風格分享圖 ══
  var _origGenerateCard = (typeof generateResultCard === 'function') ? generateResultCard : null;

  generateResultCard = function() {
    var canvas = document.createElement('canvas');
    var W = 750, H = 1334;
    canvas.width = W; canvas.height = H;
    var ctx = canvas.getContext('2d');

    // ── 背景：深色漸層 ──
    var grad = ctx.createLinearGradient(0, 0, 0, H);
    grad.addColorStop(0, '#1a0808'); grad.addColorStop(0.4, '#2a0f0f'); grad.addColorStop(1, '#0d0404');
    ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);

    // ── 裝飾邊框 ──
    ctx.strokeStyle = 'rgba(212,175,55,0.35)'; ctx.lineWidth = 2;
    ctx.strokeRect(28, 28, W - 56, H - 56);
    ctx.strokeStyle = 'rgba(212,175,55,0.1)'; ctx.lineWidth = 1;
    ctx.strokeRect(40, 40, W - 80, H - 80);

    // ── 頂部品牌 ──
    ctx.fillStyle = '#D4AF37'; ctx.font = 'bold 28px "Noto Serif TC",serif'; ctx.textAlign = 'center';
    ctx.fillText('☽ 靜月之光', W / 2, 85);
    ctx.font = '14px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.45)';
    ctx.fillText('七套命理交叉驗證', W / 2, 112);

    // ── 金色分隔線 ──
    function _goldLine(y) {
      var g = ctx.createLinearGradient(60, y, W - 60, y);
      g.addColorStop(0, 'transparent'); g.addColorStop(0.5, 'rgba(212,175,55,0.5)'); g.addColorStop(1, 'transparent');
      ctx.strokeStyle = g; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(60, y); ctx.lineTo(W - 60, y); ctx.stroke();
    }
    _goldLine(130);

    // ── 問題 ──
    var question = (S.form && S.form.question) ? S.form.question : '綜合運勢';
    var typeMap = { love: '感情', career: '事業', wealth: '財運', health: '健康', relationship: '人際', family: '家庭', general: '綜合' };
    var typeLabel = typeMap[(S.form && S.form.type) || 'general'] || '綜合';
    ctx.textAlign = 'center'; ctx.font = '16px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(212,175,55,0.7)';
    ctx.fillText('【' + typeLabel + '】', W / 2, 160);
    ctx.font = '20px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.9)';
    _wrapCenter(ctx, question, W / 2, 192, W - 140, 28);

    // ── AI 回答摘要 ──
    var aiEl = document.querySelector('#r-answer .ai-spotlight');
    var y = 270;

    if (aiEl) {
      // directAnswer
      var daEl = aiEl.querySelector('div[style*="border-bottom"]');
      if (daEl && daEl.textContent.trim()) {
        ctx.fillStyle = 'rgba(212,175,55,0.08)';
        roundRect(ctx, 50, y - 10, W - 100, 70, 12); ctx.fill();
        ctx.strokeStyle = 'rgba(212,175,55,0.3)'; ctx.stroke();
        ctx.font = 'bold 24px "Noto Serif TC",serif'; ctx.fillStyle = '#D4AF37'; ctx.textAlign = 'center';
        _wrapCenter(ctx, daEl.textContent.trim(), W / 2, y + 25, W - 140, 30);
        y += 90;
      }

      // 主文段落（取前 400 字）
      var paraEls = aiEl.querySelectorAll('div[style*="line-height:1.9"]');
      if (paraEls.length) {
        ctx.font = '17px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.85)'; ctx.textAlign = 'left';
        var fullText = '';
        paraEls.forEach(function(p) { fullText += p.textContent.trim() + '\n\n'; });
        fullText = fullText.substring(0, 500).trim();
        if (fullText.length >= 500) fullText += '…';
        y = _wrapLeft(ctx, fullText, 65, y + 10, W - 130, 26);
        y += 15;
      }

      // timing
      var timingEl = aiEl.querySelector('div[style*="border-left:3px solid rgba(251"]');
      if (timingEl && timingEl.textContent.trim()) {
        ctx.fillStyle = 'rgba(251,191,36,0.06)';
        roundRect(ctx, 50, y, W - 100, 50, 8); ctx.fill();
        ctx.strokeStyle = 'rgba(251,191,36,0.2)'; ctx.stroke();
        ctx.font = '15px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(251,191,36,0.8)'; ctx.textAlign = 'left';
        var timingText = timingEl.textContent.trim().substring(0, 80);
        ctx.fillText(timingText, 65, y + 30);
        y += 65;
      }
    } else {
      // fallback: 沒有 AI 結果，用離線資料
      if (_origGenerateCard) return _origGenerateCard();
      ctx.font = '18px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.textAlign = 'center';
      ctx.fillText('（等待解讀中…）', W / 2, y + 30);
      y += 80;
    }

    // ── 水晶推薦（簡要）──
    if (S.bazi && S.bazi.fav) {
      y = Math.max(y, 900);
      _goldLine(y);
      y += 25;
      ctx.font = 'bold 18px "Noto Sans TC",sans-serif'; ctx.fillStyle = '#D4AF37'; ctx.textAlign = 'center';
      ctx.fillText('💎 推薦能量：' + S.bazi.fav.slice(0, 2).join('+') + '行', W / 2, y + 5);
      y += 35;
    }

    // ── 底部 CTA ──
    y = Math.max(y, 1080);
    _goldLine(y);
    y += 30;
    ctx.fillStyle = 'rgba(212,175,55,0.06)';
    roundRect(ctx, W / 2 - 180, y, 360, 90, 14); ctx.fill();
    ctx.strokeStyle = 'rgba(212,175,55,0.25)'; ctx.stroke();
    ctx.font = 'bold 18px "Noto Serif TC",serif'; ctx.fillStyle = '#D4AF37'; ctx.textAlign = 'center';
    ctx.fillText('🌙 免費測你的命理結果', W / 2, y + 30);
    ctx.font = '13px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.5)';
    ctx.fillText('jingyue.uk', W / 2, y + 55);
    ctx.font = '12px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.35)';
    ctx.fillText('八字 · 紫微 · 梅花 · 塔羅 · 星盤 · 吠陀 · 姓名', W / 2, y + 75);

    // ── Footer ──
    ctx.font = '11px "Noto Sans TC",sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.25)'; ctx.textAlign = 'center';
    ctx.fillText('🛒 蝦皮: tw.shp.ee/2n5Mo2w ｜ 📦 7-11賣貨便', W / 2, H - 45);
    ctx.fillText(new Date().toLocaleDateString('zh-TW') + ' 生成', W / 2, H - 28);

    return canvas;
  };

  // 輔助：置中換行
  function _wrapCenter(ctx, text, cx, y, maxW, lineH) {
    var chars = Array.from(text); var line = '';
    for (var i = 0; i < chars.length; i++) {
      var test = line + chars[i];
      if (ctx.measureText(test).width > maxW && line) {
        ctx.fillText(line, cx, y); y += lineH; line = chars[i];
      } else { line = test; }
    }
    if (line) ctx.fillText(line, cx, y);
    return y + lineH;
  }

  // 輔助：左對齊換行（回傳結束 y）
  function _wrapLeft(ctx, text, x, y, maxW, lineH) {
    var lines = text.split('\n');
    for (var li = 0; li < lines.length; li++) {
      var chars = Array.from(lines[li]); var line = '';
      for (var i = 0; i < chars.length; i++) {
        var test = line + chars[i];
        if (ctx.measureText(test).width > maxW && line) {
          ctx.fillText(line, x, y); y += lineH; line = chars[i];
        } else { line = test; }
      }
      if (line) { ctx.fillText(line, x, y); y += lineH; }
      if (li < lines.length - 1 && !lines[li]) y += lineH * 0.3; // 段落間距
    }
    return y;
  }

  console.log('[Patch v2] 離線模式已升級：命盤摘要卡 + AI 英雄按鈕');
})();
